import React, { useState, useRef, useEffect } from 'react';
import { TOTAL_SLICES, CHAPTER_DETAILS } from '../constants.ts';
import { colorScale, polarToCartesian } from '../utils.ts';

interface AstrolabeModeProps {
  onClose: () => void;
}

const AstrolabeMode: React.FC<AstrolabeModeProps> = ({ onClose }) => {
  const [reteRotation, setReteRotation] = useState(0);
  const [alidadeRotation, setAlidadeRotation] = useState(45);
  const [isDraggingRete, setIsDraggingRete] = useState(false);
  const [isDraggingAlidade, setIsDraggingAlidade] = useState(false);
  const svgRef = useRef<SVGSVGElement>(null);

  const getAngle = (clientX: number, clientY: number) => {
    if (!svgRef.current) return 0;
    const rect = svgRef.current.getBoundingClientRect();
    const centerX = rect.left + rect.width / 2;
    const centerY = rect.top + rect.height / 2;
    return Math.atan2(clientY - centerY, clientX - centerX) * (180 / Math.PI) + 90;
  };

  const handlePointerDown = (e: React.PointerEvent, target: 'rete' | 'alidade') => {
    e.stopPropagation();
    if (target === 'rete') setIsDraggingRete(true);
    else setIsDraggingAlidade(true);
  };

  useEffect(() => {
    const handlePointerMove = (e: PointerEvent) => {
      if (isDraggingRete) {
        setReteRotation(getAngle(e.clientX, e.clientY));
      } else if (isDraggingAlidade) {
        setAlidadeRotation(getAngle(e.clientX, e.clientY));
      }
    };

    const handlePointerUp = () => {
      setIsDraggingRete(false);
      setIsDraggingAlidade(false);
    };

    if (isDraggingRete || isDraggingAlidade) {
      window.addEventListener('pointermove', handlePointerMove);
      window.addEventListener('pointerup', handlePointerUp);
    }

    return () => {
      window.removeEventListener('pointermove', handlePointerMove);
      window.removeEventListener('pointerup', handlePointerUp);
    };
  }, [isDraggingRete, isDraggingAlidade]);

  const center = 250;
  const outerRadius = 240;
  const innerRadius = 220;

  return (
    <div className="fixed inset-0 z-[200] flex items-center justify-center bg-black/90 backdrop-blur-xl animate-in fade-in zoom-in duration-500 overflow-hidden">
      <div className="absolute top-6 left-1/2 -translate-x-1/2 text-center pointer-events-none">
        <h2 className="text-3xl font-black text-cyan-400 tracking-tighter uppercase italic drop-shadow-[0_0_10px_rgba(6,182,212,0.5)]">
          Celestial Astrolabe
        </h2>
        <p className="text-gray-500 text-sm tracking-[0.3em] uppercase mt-1">
          Mapping the 114 Dimensions of Reality
        </p>
      </div>

      <button onClick={onClose} className="absolute top-6 right-6 p-4 rounded-full bg-white/5 text-gray-400 hover:text-white transition-all hover:bg-white/10 z-[210]">
        <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={3}>
          <path strokeLinecap="round" strokeLinejoin="round" d="M6 18L18 6M6 6l12 12" />
        </svg>
      </button>

      <div className="relative w-full max-w-[90vh] aspect-square flex items-center justify-center p-4">
        <svg 
          ref={svgRef}
          viewBox="0 0 500 500" 
          className="w-full h-full drop-shadow-[0_0_50px_rgba(6,182,212,0.1)]"
        >
          {/* Mater (Outer Rim) */}
          <circle cx={center} cy={center} r={outerRadius} fill="none" stroke="rgba(245, 158, 11, 0.4)" strokeWidth="12" />
          <circle cx={center} cy={center} r={outerRadius - 6} fill="none" stroke="rgba(0, 0, 0, 0.5)" strokeWidth="1" />

          {/* Degree Marks / Chapter Marks */}
          {Array.from({ length: 114 }).map((_, i) => {
            const angle = (i / 114) * 360;
            const p1 = polarToCartesian(center, center, outerRadius - 6, angle);
            const p2 = polarToCartesian(center, center, outerRadius + 6, angle);
            const color = colorScale(i + 1);
            return (
              <line key={i} x1={p1.x} y1={p1.y} x2={p2.x} y2={p2.y} stroke={color} strokeWidth={i % 10 === 0 ? "2" : "0.5"} />
            );
          })}

          {/* Plate (Tympan) - Fixed Grid */}
          <g opacity="0.3">
            <circle cx={center} cy={center} r={innerRadius} fill="none" stroke="rgba(255,255,255,0.1)" strokeWidth="1" />
            {Array.from({ length: 12 }).map((_, i) => {
              const r = (innerRadius / 12) * (i + 1);
              return <circle key={i} cx={center} cy={center} r={r} fill="none" stroke="rgba(255,255,255,0.05)" strokeWidth="1" />;
            })}
            {Array.from({ length: 36 }).map((_, i) => {
              const angle = i * 10;
              const p1 = polarToCartesian(center, center, 0, angle);
              const p2 = polarToCartesian(center, center, innerRadius, angle);
              return <line key={i} x1={p1.x} y1={p1.y} x2={p2.x} y2={p2.y} stroke="rgba(255,255,255,0.05)" strokeWidth="1" />;
            })}
          </g>

          {/* Rete (Rotating Star Map) */}
          <g 
            transform={`rotate(${reteRotation} ${center} ${center})`}
            onPointerDown={(e) => handlePointerDown(e, 'rete')}
            className="cursor-grab active:cursor-grabbing"
          >
            <circle cx={center} cy={center} r={innerRadius - 10} fill="rgba(6, 182, 212, 0.05)" stroke="rgba(6, 182, 212, 0.4)" strokeWidth="2" />
            {/* Star Pointers */}
            {CHAPTER_DETAILS.slice(0, 19).map((ch, i) => {
              const angle = (i / 19) * 360;
              const r = (innerRadius - 40) - (i * 2);
              const p = polarToCartesian(center, center, r, angle);
              return (
                <g key={i}>
                  <line x1={center} y1={center} x2={p.x} y2={p.y} stroke="rgba(6, 182, 212, 0.1)" strokeWidth="1" />
                  <circle cx={p.x} cy={p.y} r="3" fill="#06b6d4" className="animate-pulse" />
                  <text 
                    x={p.x + 8} y={p.y} 
                    fontSize="6" fill="#06b6d4" fontWeight="bold" className="uppercase"
                    transform={`rotate(${-reteRotation} ${p.x} ${p.y})`}
                  >
                    {ch.englishName}
                  </text>
                </g>
              );
            })}
            {/* The Ecliptic Circle (Offset) */}
            <circle cx={center} cy={center + 40} r={80} fill="none" stroke="rgba(217, 70, 239, 0.4)" strokeWidth="2" />
          </g>

          {/* Alidade (Ruler) */}
          <g 
            transform={`rotate(${alidadeRotation} ${center} ${center})`}
            onPointerDown={(e) => handlePointerDown(e, 'alidade')}
            className="cursor-grab active:cursor-grabbing"
          >
            <rect x={center - 4} y={center - outerRadius - 20} width="8" height={(outerRadius + 20) * 2} fill="rgba(245, 158, 11, 0.8)" rx="4" />
            <circle cx={center} cy={center - outerRadius - 10} r="6" fill="#f59e0b" stroke="white" strokeWidth="2" />
            <circle cx={center} cy={center + outerRadius + 10} r="6" fill="#f59e0b" stroke="white" strokeWidth="2" />
            {/* Sighting lines */}
            <line x1={center} y1={center - outerRadius - 20} x2={center} y2={center + outerRadius + 20} stroke="white" strokeWidth="0.5" strokeDasharray="2 2" />
          </g>

          {/* Center Pin */}
          <circle cx={center} cy={center} r="8" fill="#111" stroke="#f59e0b" strokeWidth="2" />
          <circle cx={center} cy={center} r="2" fill="white" />
        </svg>

        {/* Dynamic Readout */}
        <div className="absolute bottom-10 left-10 flex flex-col gap-1 font-mono text-xs pointer-events-none">
          <div className="flex gap-2">
            <span className="text-gray-500 uppercase">Rete:</span>
            <span className="text-cyan-400">{reteRotation.toFixed(1)}°</span>
          </div>
          <div className="flex gap-2">
            <span className="text-gray-500 uppercase">Alidade:</span>
            <span className="text-amber-500">{alidadeRotation.toFixed(1)}°</span>
          </div>
        </div>

        <div className="absolute bottom-10 right-10 text-right pointer-events-none">
          <p className="text-[10px] text-fuchsia-400 uppercase tracking-widest font-black">Interactive Phase Sync</p>
          <p className="text-gray-500 text-[9px] mt-1 italic">Drag rings and ruler to align cosmic vectors</p>
        </div>
      </div>
    </div>
  );
};

