}

interface SightingData {
  coordinate: string;
  altitude: number;
  azimuth: number;
  density: number;
  guardStatus: string;
  kingdomProximity: number;
  binaryAddress: string;
  entropy: 'Rahman (Wave)' | 'Rahim (Particle)';
}

const AstrolabeMode: React.FC<AstrolabeModeProps> = ({ onClose }) => {
