  const [isDraggingAlidade, setIsDraggingAlidade] = useState(false);
  const svgRef = useRef<SVGSVGElement>(null);

  // Constants from User Prompt
  const HORIZON_LIMIT = 286;
  const PHI = 1.618;

  const calculateSighting = (coord: string): SightingData | null => {
    const parts = coord.split(':').map(Number);
    const surah = parts[0];
    const verse = parts[1] || 1;

    if (isNaN(surah) || surah < 1 || surah > 114) return null;

    const chapterInfo = CHAPTER_DETAILS[surah - 1];
    const maxVerses = chapterInfo ? chapterInfo.number === 2 ? 286 : 286 : 286; // Logic uses 286 as absolute limit

    // 1. Vector Altitude: 90 - ((V / 286) * 90)
    const altitude = 90 - ((verse / HORIZON_LIMIT) * 90);

    // 2. Vector Azimuth: (C / 114) * 360
    const azimuth = (surah / 114) * 360;

    // 3. Density
    const density = verse / HORIZON_LIMIT;

    // 4. 37:7 Guard
    const guardStatus = altitude < 15 ? 'FLAGGED: Near Abyss' : 'INTEGRITY INTACT';

    // 5. Kingdom Proximity (Distance to 12:100)
    const targetAz = (12 / 114) * 360;
    const targetAlt = 90 - ((100 / 286) * 90);
    const kingdomProximity = Math.sqrt(Math.pow(azimuth - targetAz, 2) + Math.pow(altitude - targetAlt, 2));

    // 6. Entropy Gradient
    const entropy = verse % 2 === 0 ? 'Rahman (Wave)' : 'Rahim (Particle)';

    // 7. Binary Address (Mock bits based on coordinate)
    const binaryAddress = `${surah.toString(2).padStart(7, '0')}-${verse.toString(2).padStart(9, '0')}-00000000000000-00000`;

    return {
      coordinate: `${surah}:${verse}`,
      altitude,
      azimuth,
      density,
      guardStatus,
      kingdomProximity,
      binaryAddress,
      entropy
    };
  };

