            {/* Muqatta'at Positions */}
            {Array.from(MUQATTAT_CHAPTERS).map((chId, i) => {
              const angle = (chId / 114) * 360;
              const r = (innerRadius - 30) - (i % 5 * 10);
              const p = polarToCartesian(center, center, r, angle);
              return (
                <g key={chId}>
                  <line x1={center} y1={center} x2={p.x} y2={p.y} stroke="rgba(6, 182, 212, 0.1)" strokeWidth="0.5" />
                  <circle cx={p.x} cy={p.y} r="2" fill="#06b6d4" className="animate-pulse" />
                </g>
              );
