                          <g className="animate-in zoom-in fade-in duration-1000">
                              <circle cx={p.x} cy={p.y} r="6" fill="none" stroke="#f59e0b" strokeWidth="2">
                                  <animate attributeName="r" values="6;10;6" dur="2s" repeatCount="indefinite" />
                              </circle>
                              <circle cx={p.x} cy={p.y} r="2" fill="white" />
                          </g>
                      );
                  })()}
              </g>
          )}

          {/* Alidade (Rotating Alidade: Sighting Ruler) */}
          <g 
            transform={`rotate(${alidadeRotation} ${center} ${center})`}
            onPointerDown={(e) => handlePointerDown(e, 'alidade')}
            className="cursor-grab active:cursor-grabbing transition-transform duration-1000 ease-out"
          >
            <rect x={center - 3} y={center - outerRadius - 15} width="6" height={(outerRadius + 15) * 2} fill="rgba(245, 158, 11, 0.7)" rx="3" />
