            <circle cx={center} cy={center + outerRadius + 5} r="5" fill="#f59e0b" stroke="white" strokeWidth="1.5" />
            <line x1={center} y1={center - outerRadius - 15} x2={center} y2={center + outerRadius + 15} stroke="white" strokeWidth="0.5" strokeDasharray="1 1" />
          </g>

          {/* Center Pin (The Point of Origin) */}
          <circle cx={center} cy={center} r={10} fill="#111" stroke="#f59e0b" strokeWidth="2" />
          <circle cx={center} cy={center} r={3} fill="#f59e0b" className="animate-pulse" />
        </svg>

        {/* Floating Instructions */}
        <div className="absolute top-10 right-10 text-right pointer-events-none hidden lg:block">
