import React, { useState, useRef, useEffect, useMemo } from 'react';
import { TOTAL_SLICES, CHAPTER_DETAILS, MUQATTAT_CHAPTERS } from '../constants.ts';
import { polarToCartesian } from '../utils.ts';

interface AstrolabeModeProps {
  onClose: () => void;
}

interface SightingData {
  front: {
    coordinate: string;
    lightFreq: string;
    zenithAngle: number;
    altitude: number;
    gestation: number; // 0-100%
  };
  back: {
    shadowTangent: number;
    shadowCotangent: number;
    waveEntropy: number;
    zodiacHouse: number;
    barrierStatus: 'OPEN' | 'LOCKED';
    centerDist: number;
    symmetryViolation: number; // 0 or 1
  };
}

const AstrolabeMode: React.FC<AstrolabeModeProps> = ({ onClose }) => {
  const [query, setQuery] = useState('12:100');
  const [sighting, setSighting] = useState<SightingData | null>(null);
  const [activeSide, setActiveSide] = useState<'FRONT' | 'BACK'>('FRONT');
  const [reteRotation, setReteRotation] = useState(0);
  const [alidadeRotation, setAlidadeRotation] = useState(0);
  const [isDraggingRete, setIsDraggingRete] = useState(false);
  const [isDraggingAlidade, setIsDraggingAlidade] = useState(false);
  const svgRef = useRef<SVGSVGElement>(null);

  const HORIZON_LIMIT = 286;
  const PHI = 1.618;

  const calculateSighting = (coord: string): SightingData | null => {
    const parts = coord.split(':').map(Number);
    const C = parts[0];
    const V = parts[1] || 1;

    if (isNaN(C) || C < 1 || C > 114) return null;

    // FRONT SIDE CALCULATIONS
    const altitude = 90 - ((V / HORIZON_LIMIT) * 90);
    const azimuth = (C / 114) * 360;
    const zenithAngle = 90 - altitude;
    const isMuqattat = MUQATTAT_CHAPTERS.has(C);
    const lightFreq = isMuqattat ? (PHI * (C / 114)).toFixed(4) : "0.0000";
    const gestation = (V / HORIZON_LIMIT) * 100;

    // BACK SIDE CALCULATIONS
    const radAlt = (altitude * Math.PI) / 180;
    // Tangent/Cotangent logic (Inverse Shadow)
    // 12:100 (Altitude high) -> Shadow small
    // 14:22 (Altitude low) -> Shadow large
    const shadowTangent = altitude === 0 ? 999.99 : Math.tan((90 - altitude) * Math.PI / 180);
    const shadowCotangent = altitude === 90 ? 0.00 : 1 / Math.tan(radAlt);

    const waveEntropy = Math.sin((azimuth * Math.PI) / 180);

    // Zodiac of Surahs: 12 Houses, Ch 12 is 0-point
    const zodiacHouse = Math.floor(((C - 12 + 114) % 114) / 9.5) + 1;

    // 37:7 Barrier
    const barrierStatus = altitude < 15 ? 'LOCKED' : 'OPEN';

    // Distance to Center Pin (Normalized 0-1)
    const centerDist = altitude / 90;

    // Parity Symmetry Check (Entropy)
    const symmetryViolation = (C % 2 === V % 2) ? 0 : 1;

    return {
      front: {
        coordinate: `${C}:${V}`,
        lightFreq,
        zenithAngle,
        altitude,
        gestation
      },
      back: {
        shadowTangent,
        shadowCotangent,
        waveEntropy,
        zodiacHouse,
        barrierStatus,
        centerDist,
        symmetryViolation
      }
    };
  };

  useEffect(() => {
    const initialSighting = calculateSighting(query);
    if (initialSighting) {
      setSighting(initialSighting);
      setAlidadeRotation((parseInt(query.split(':')[0]) / 114) * 360);
    }
  }, []);

  const handleSearch = (e: React.FormEvent) => {
    e.preventDefault();
    const result = calculateSighting(query);
    if (result) {
      setSighting(result);
      setAlidadeRotation((parseInt(query.split(':')[0]) / 114) * 360);
    }
  };

  const getAngle = (clientX: number, clientY: number) => {
    if (!svgRef.current) return 0;
    const rect = svgRef.current.getBoundingClientRect();
    const centerX = rect.left + rect.width / 2;
    const centerY = rect.top + rect.height / 2;
    return Math.atan2(clientY - centerY, clientX - centerX) * (180 / Math.PI) + 90;
  };

  const handlePointerDown = (e: React.PointerEvent, target: 'rete' | 'alidade') => {
    e.stopPropagation();
    if (target === 'rete') setIsDraggingRete(true);
    else setIsDraggingAlidade(true);
  };

