        <div className="flex justify-between items-center border-b border-white/5 pb-4">
          <div>
            <h2 className="text-3xl font-black text-white tracking-tighter uppercase italic leading-none">MIZAN-114</h2>
            <p className="text-cyan-600 text-[10px] font-bold tracking-[0.4em] uppercase mt-2">Instrument of Dual Caustics</p>
          </div>
          <button onClick={onClose} className="p-3 rounded-full bg-white/5 text-gray-600 hover:text-white transition-colors border border-white/5 hover:border-white/20">
            <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6" fill="none" viewBox="0 0 24 24" stroke="currentColor">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M6 18L18 6M6 6l12 12" />
            </svg>
          </button>
        </div>

        <div className="flex gap-2 p-1 bg-black/40 rounded-xl border border-white/5 shadow-inner">
            <button 
              onClick={() => setActiveSide('FRONT')}
              className={`flex-1 py-2 text-[10px] font-black uppercase tracking-widest rounded-lg transition-all ${activeSide === 'FRONT' ? 'bg-cyan-600/20 text-cyan-400 border border-cyan-500/30' : 'text-gray-500 hover:text-gray-300'}`}
            >
              Side A: Celestial
            </button>
            <button 
              onClick={() => setActiveSide('BACK')}
              className={`flex-1 py-2 text-[10px] font-black uppercase tracking-widest rounded-lg transition-all ${activeSide === 'BACK' ? 'bg-fuchsia-600/20 text-fuchsia-400 border border-fuchsia-500/30' : 'text-gray-500 hover:text-gray-300'}`}
            >
              Side B: Math
            </button>
        </div>

        <div className="flex flex-col gap-3">
          <form onSubmit={handleSearch} className="relative group">
            <input 
              type="text" 
              value={query} 
              onChange={(e) => setQuery(e.target.value)}
              placeholder="[ C : V ]"
              className="w-full bg-black border border-white/10 rounded-xl px-6 py-4 text-cyan-400 font-mono text-xl focus:outline-none focus:border-cyan-500 transition-all placeholder:text-zinc-800 shadow-[inset_0_0_15px_rgba(0,0,0,1)]"
            />
            <button type="submit" className="absolute right-3 top-1/2 -translate-y-1/2 bg-cyan-600 hover:bg-cyan-500 text-black font-black px-4 py-2 rounded-lg transition-all uppercase text-[10px] tracking-widest shadow-xl active:scale-95">Sight</button>
          </form>

          <div className="flex gap-2 h-12">
            <button 
              onClick={() => handleStep(-1)}
              className="flex-1 bg-zinc-900 border border-white/5 hover:border-cyan-500/30 text-white rounded-xl font-black text-xl transition-all active:scale-95"
              title="Previous Verse"
            >
              -
            </button>
            <button 
              onClick={handleRandom}
              className="w-16 bg-zinc-900 border border-white/5 hover:border-cyan-500/30 text-cyan-400 flex items-center justify-center rounded-xl transition-all active:scale-95"
              title="Random Coordinate"
            >
              <ShuffleIcon />
            </button>
            <button 
              onClick={() => handleStep(1)}
              className="flex-1 bg-zinc-900 border border-white/5 hover:border-cyan-500/30 text-white rounded-xl font-black text-xl transition-all active:scale-95"
              title="Next Verse"
            >
              +
            </button>
          </div>
        </div>

        {sighting && (
          <div className="space-y-8 animate-in fade-in slide-in-from-bottom duration-1000">
            {activeSide === 'FRONT' ? (
              <div className="space-y-6">
                <div className="flex items-center gap-4">
