               {Array.from({ length: 12 }).map((_, i) => (
                 <React.Fragment key={i}>
                   <line x1={center - 120} y1={center - 120 + i*20} x2={center + 120} y2={center - 120 + i*20} stroke="rgba(255,255,255,0.05)" strokeWidth="0.5" />
                   <line x1={center - 120 + i*20} y1={center - 120} x2={center - 120 + i*20} y2={center + 120} stroke="rgba(255,255,255,0.05)" strokeWidth="0.5" />
                 </React.Fragment>
               ))}
            </g>
          ) : (
            <g opacity="0.3">
               <line x1={center} y1={center - outerRadius} x2={center} y2={center + outerRadius} stroke="rgba(34, 211, 238, 0.2)" strokeWidth="1" strokeDasharray="4 4" />
               <line x1={center - outerRadius} y1={center} x2={center + outerRadius} y2={center} stroke="rgba(34, 211, 238, 0.2)" strokeWidth="1" strokeDasharray="4 4" />
            </g>
          )}

          <g 
            transform={`rotate(${reteRotation} ${center} ${center})`}
            onPointerDown={(e) => handlePointerDown(e, 'rete')}
            className="cursor-grab active:cursor-grabbing"
          >
             <circle cx={center} cy={center} r={innerRadius - 10} fill="none" stroke="rgba(34, 211, 238, 0.15)" strokeWidth="1.5" />
             <circle cx={center} cy={center + 35} r={85} fill="none" stroke="rgba(245, 158, 11, 0.1)" strokeWidth="2" />

             {CHAPTER_DETAILS.map((ch, i) => {
               if (i % 6 !== 0) return null;
               const angle = (i / 114) * 360;
               const r = innerRadius - 40 - (Math.sin(i) * 20);
               const p = polarToCartesian(center, center, r, angle);
               const isMuqattat = MUQATTAT_CHAPTERS.has(ch.number);
               return (
                 <g key={i}>
                   <path d={`M ${center} ${center} L ${p.x} ${p.y}`} stroke="rgba(255,255,255,0.05)" strokeWidth="0.5" />
                   <circle cx={p.x} cy={p.y} r={isMuqattat ? 3 : 1.5} fill={isMuqattat ? "#06b6d4" : "#444"} className={isMuqattat ? 'animate-pulse' : ''} />
                 </g>
               );
             })}
          </g>

          {sighting && (
            <g className="animate-in fade-in zoom-in duration-1000">
               {(() => {
                  const angle = (parseInt(sighting.front.coordinate.split(':')[0]) / 114) * 360;
                  const radius = (innerRadius * sighting.front.altitude) / 90;
                  const p = polarToCartesian(center, center, radius, angle);
                  return (
                    <g>
                       <circle cx={p.x} cy={p.y} r="12" fill="none" stroke={activeSide === 'FRONT' ? "#06b6d4" : "#d946ef"} strokeWidth="1" strokeDasharray="2 2" className="animate-[spin_10s_linear_infinite]" />
                       <circle cx={p.x} cy={p.y} r="4" fill={activeSide === 'FRONT' ? "#06b6d4" : "#d946ef"} className="shadow-[0_0_15px_currentColor]" />
                       <line x1={center} y1={center} x2={p.x} y2={p.y} stroke={activeSide === 'FRONT' ? "#06b6d4" : "#d946ef"} strokeWidth="0.5" strokeOpacity="0.5" />
                    </g>
                  );
               })()}
            </g>
          )}

          <g 
            transform={`rotate(${alidadeRotation} ${center} ${center})`}
            onPointerDown={(e) => handlePointerDown(e, 'alidade')}
            className="cursor-grab active:cursor-grabbing transition-transform duration-700 ease-out"
          >
            <rect x={center - 3.5} y={center - outerRadius - 10} width="7" height={(outerRadius + 10) * 2} fill="#2a2b35" rx="3.5" />
            <rect x={center - 1.5} y={center - outerRadius - 10} width="3" height={(outerRadius + 10) * 2} fill="#f59e0b" opacity="0.6" />

            <circle cx={center} cy={center - outerRadius + 10} r="4" fill="black" stroke="#f59e0b" strokeWidth="1" />
            <circle cx={center} cy={center + outerRadius - 10} r="4" fill="black" stroke="#f59e0b" strokeWidth="1" />

            <circle cx={center} cy={center} r={12} fill="#1a1b21" stroke="#f59e0b" strokeWidth="2" />
            <circle cx={center} cy={center} r={3} fill="#f59e0b" className="animate-pulse" />
          </g>
        </svg>

        <div className="absolute top-10 right-10 flex flex-col items-end pointer-events-none">
           <span className="text-cyan-400 font-black text-xl tracking-tighter uppercase italic">Phase Sync</span>
           <span className="text-gray-700 text-[10px] uppercase font-bold tracking-widest mt-1">Instrument Calibrated: 286-Horizon</span>
        </div>
      </main>
    </div>
  );
};

export default AstrolabeMode;

import React, { useState, useRef, useEffect, useMemo } from 'react';
import { TOTAL_SLICES, CHAPTER_DETAILS, MUQATTAT_CHAPTERS, BUBBLE_BLOCK_MAPPING_RAW } from '../constants.ts';
import { polarToCartesian } from '../utils.ts';
import { ShuffleIcon } from './Icons.tsx';

interface AstrolabeModeProps {
  onClose: () => void;
}

interface SightingData {
  front: {
    coordinate: string;
    lightFreq: string;
    zenithAngle: number;
    altitude: number;
    gestation: number; // 0-100%
  };
  back: {
    shadowTangent: number;
    shadowCotangent: number;
    waveEntropy: number;
    zodiacHouse: number;
    barrierStatus: 'OPEN' | 'LOCKED';
    centerDist: number;
    symmetryViolation: number; // 0 or 1
  };
}

const AstrolabeMode: React.FC<AstrolabeModeProps> = ({ onClose }) => {
  const [query, setQuery] = useState('12:100');
  const [sighting, setSighting] = useState<SightingData | null>(null);
  const [activeSide, setActiveSide] = useState<'FRONT' | 'BACK'>('FRONT');
  const [reteRotation, setReteRotation] = useState(0);
  const [alidadeRotation, setAlidadeRotation] = useState(0);
  const [isDraggingRete, setIsDraggingRete] = useState(false);
  const [isDraggingAlidade, setIsDraggingAlidade] = useState(false);

  const alidadeRotationRef = useRef(0);
  const svgRef = useRef<SVGSVGElement>(null);

  const HORIZON_LIMIT = 286;
  const PHI = 1.618;

  const calculateSighting = (coord: string): SightingData | null => {
    const parts = coord.split(':').map(Number);
    const C = parts[0];
    const V = parts[1] || 1;

    if (isNaN(C) || C < 1 || C > 114) return null;

    // FRONT SIDE CALCULATIONS
    const altitude = 90 - ((V / HORIZON_LIMIT) * 90);
    const azimuth = (C / 114) * 360;
    const zenithAngle = 90 - altitude;
    const isMuqattat = MUQATTAT_CHAPTERS.has(C);
    const lightFreq = isMuqattat ? (PHI * (C / 114)).toFixed(4) : "0.0000";
    const gestation = (V / HORIZON_LIMIT) * 100;

    // BACK SIDE CALCULATIONS
    const radAlt = (altitude * Math.PI) / 180;
    const shadowTangent = altitude === 0 ? 999.99 : Math.tan((90 - altitude) * Math.PI / 180);
    const shadowCotangent = altitude === 90 ? 0.00 : 1 / Math.tan(radAlt);

    const waveEntropy = Math.sin((azimuth * Math.PI) / 180);
    const zodiacHouse = Math.floor(((C - 12 + 114) % 114) / 9.5) + 1;
    const barrierStatus = altitude < 15 ? 'LOCKED' : 'OPEN';
    const centerDist = altitude / 90;
    const symmetryViolation = (C % 2 === V % 2) ? 0 : 1;

    return {
      front: {
        coordinate: `${C}:${V}`,
        lightFreq,
        zenithAngle,
        altitude,
        gestation
      },
      back: {
        shadowTangent,
        shadowCotangent,
        waveEntropy,
        zodiacHouse,
        barrierStatus,
        centerDist,
        symmetryViolation
      }
    };
  };

  const getShortestRotation = (current: number, target: number) => {
    const normalize = (angle: number) => ((angle % 360) + 360) % 360;
    const currNormalized = normalize(current);
    const targetNormalized = normalize(target);
    let diff = targetNormalized - currNormalized;

    if (diff > 180) diff -= 360;
    if (diff < -180) diff += 360;

    return current + diff;
  };

  const updateWithCoord = (coord: string) => {
    const result = calculateSighting(coord);
    if (result) {
      setSighting(result);
      const targetAzimuth = (parseInt(coord.split(':')[0]) / 114) * 360;
      const smoothRotation = getShortestRotation(alidadeRotationRef.current, targetAzimuth);

      alidadeRotationRef.current = smoothRotation;
      setAlidadeRotation(smoothRotation);
      setQuery(coord);
    }
  };

  useEffect(() => {
    updateWithCoord(query);
  }, []);

  const handleSearch = (e: React.FormEvent) => {
    e.preventDefault();
    updateWithCoord(query);
  };

  const handleRandom = () => {
    const randomSurah = Math.floor(Math.random() * 114) + 1;
    const maxAyahs = BUBBLE_BLOCK_MAPPING_RAW[randomSurah as keyof typeof BUBBLE_BLOCK_MAPPING_RAW] || 7;
    const randomAyah = Math.floor(Math.random() * maxAyahs) + 1;
    updateWithCoord(`${randomSurah}:${randomAyah}`);
  };

  const handleStep = (delta: number) => {
    const parts = query.split(':').map(Number);
    const C = parts[0];
    let V = parts[1] || 1;
    const maxAyahs = BUBBLE_BLOCK_MAPPING_RAW[C as keyof typeof BUBBLE_BLOCK_MAPPING_RAW] || 286;

    V += delta;
    if (V < 1) V = 1;
    if (V > maxAyahs) V = maxAyahs;

    updateWithCoord(`${C}:${V}`);
  };

  const getAngle = (clientX: number, clientY: number) => {
    if (!svgRef.current) return 0;
    const rect = svgRef.current.getBoundingClientRect();
    const centerX = rect.left + rect.width / 2;
    const centerY = rect.top + rect.height / 2;
    return Math.atan2(clientY - centerY, clientX - centerX) * (180 / Math.PI) + 90;
  };

  const handlePointerDown = (e: React.PointerEvent, target: 'rete' | 'alidade') => {
    e.stopPropagation();
    if (target === 'rete') setIsDraggingRete(true);
    else setIsDraggingAlidade(true);
  };

  useEffect(() => {
    const handlePointerMove = (e: PointerEvent) => {
      if (isDraggingRete) setReteRotation(getAngle(e.clientX, e.clientY));
      else if (isDraggingAlidade) {
        const angle = getAngle(e.clientX, e.clientY);
        setAlidadeRotation(angle);
        alidadeRotationRef.current = angle;
      }
    };
    const handlePointerUp = () => {
      setIsDraggingRete(false);
      setIsDraggingAlidade(false);
    };
    if (isDraggingRete || isDraggingAlidade) {
      window.addEventListener('pointermove', handlePointerMove);
      window.addEventListener('pointerup', handlePointerUp);
    }
    return () => {
      window.removeEventListener('pointermove', handlePointerMove);
      window.removeEventListener('pointerup', handlePointerUp);
    };
  }, [isDraggingRete, isDraggingAlidade]);

  const center = 250;
  const outerRadius = 240;
  const innerRadius = 220;

  return (
    <div className="fixed inset-0 z-[200] flex flex-col lg:flex-row bg-[#020306] animate-in fade-in zoom-in duration-500 overflow-hidden">
      {/* Sidebar: Mechanical Readout */}
      <aside className="w-full lg:w-[400px] bg-[#05060a]/90 backdrop-blur-3xl border-b lg:border-r border-cyan-950 p-8 flex flex-col gap-6 overflow-y-auto no-scrollbar shadow-[20px_0_40px_rgba(0,0,0,0.5)]">
        <div className="flex justify-between items-center border-b border-white/5 pb-4">
          <div>
            <h2 className="text-3xl font-black text-white tracking-tighter uppercase italic leading-none">MIZAN-114</h2>
            <p className="text-cyan-600 text-[10px] font-bold tracking-[0.4em] uppercase mt-2">Instrument of Dual Caustics</p>
          </div>
          <button onClick={onClose} className="p-3 rounded-full bg-white/5 text-gray-600 hover:text-white transition-colors border border-white/5 hover:border-white/20">
            <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6" fill="none" viewBox="0 0 24 24" stroke="currentColor">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M6 18L18 6M6 6l12 12" />
            </svg>
          </button>
        </div>

        <div className="flex gap-2 p-1 bg-black/40 rounded-xl border border-white/5 shadow-inner">
            <button 
              onClick={() => setActiveSide('FRONT')}
              className={`flex-1 py-2 text-[10px] font-black uppercase tracking-widest rounded-lg transition-all ${activeSide === 'FRONT' ? 'bg-cyan-600/20 text-cyan-400 border border-cyan-500/30' : 'text-gray-500 hover:text-gray-300'}`}
            >
              Side A: Celestial
            </button>
            <button 
              onClick={() => setActiveSide('BACK')}
              className={`flex-1 py-2 text-[10px] font-black uppercase tracking-widest rounded-lg transition-all ${activeSide === 'BACK' ? 'bg-fuchsia-600/20 text-fuchsia-400 border border-fuchsia-500/30' : 'text-gray-500 hover:text-gray-300'}`}
            >
              Side B: Math
            </button>
        </div>

        <div className="flex flex-col gap-3">
          <form onSubmit={handleSearch} className="relative group">
            <input 
              type="text" 
              value={query} 
              onChange={(e) => setQuery(e.target.value)}
              placeholder="[ C : V ]"
              className="w-full bg-black border border-white/10 rounded-xl px-6 py-4 text-cyan-400 font-mono text-xl focus:outline-none focus:border-cyan-500 transition-all placeholder:text-zinc-800 shadow-[inset_0_0_15px_rgba(0,0,0,1)]"
            />
            <button type="submit" className="absolute right-3 top-1/2 -translate-y-1/2 bg-cyan-600 hover:bg-cyan-500 text-black font-black px-4 py-2 rounded-lg transition-all uppercase text-[10px] tracking-widest shadow-xl active:scale-95">Sight</button>
          </form>

          <div className="flex gap-2 h-12">
            <button 
              onClick={() => handleStep(-1)}
              className="flex-1 bg-zinc-900 border border-white/5 hover:border-cyan-500/30 text-white rounded-xl font-black text-xl transition-all active:scale-95"
              title="Previous Verse"
            >
              -
            </button>
            <button 
              onClick={handleRandom}
              className="w-16 bg-zinc-900 border border-white/5 hover:border-cyan-500/30 text-cyan-400 flex items-center justify-center rounded-xl transition-all active:scale-95"
              title="Random Coordinate"
            >
              <ShuffleIcon />
            </button>
            <button 
              onClick={() => handleStep(1)}
              className="flex-1 bg-zinc-900 border border-white/5 hover:border-cyan-500/30 text-white rounded-xl font-black text-xl transition-all active:scale-95"
              title="Next Verse"
            >
              +
            </button>
          </div>
        </div>

        {sighting && (
          <div className="space-y-8 animate-in fade-in slide-in-from-bottom duration-1000">
            {activeSide === 'FRONT' ? (
              <div className="space-y-6">
                <div className="flex items-center gap-4">
                  <div className="h-px flex-1 bg-gradient-to-r from-transparent to-cyan-500/30"></div>
                  <span className="text-[10px] font-black text-cyan-500 uppercase tracking-[0.4em]">Celestial Alignment</span>
                  <div className="h-px flex-1 bg-gradient-to-l from-transparent to-cyan-500/30"></div>
                </div>

                <div className="grid grid-cols-2 gap-4">
                  <div className="bg-zinc-950 p-4 rounded-xl border border-white/5 flex flex-col">
                    <span className="text-[9px] text-gray-600 uppercase font-black tracking-widest mb-1">Vector Altitude</span>
                    <span className="text-2xl font-mono font-bold text-white leading-none">{sighting.front.altitude.toFixed(3)}°</span>
                  </div>
                  <div className="bg-zinc-950 p-4 rounded-xl border border-white/5 flex flex-col">
                    <span className="text-[9px] text-gray-600 uppercase font-black tracking-widest mb-1">Zenith Angle</span>
                    <span className="text-2xl font-mono font-bold text-white leading-none">{sighting.front.zenithAngle.toFixed(3)}°</span>
                  </div>
                </div>

                <div className="bg-cyan-950/10 border border-cyan-500/20 p-5 rounded-2xl space-y-4">
                  <div className="flex justify-between items-center group">
                    <span className="text-[10px] text-gray-500 uppercase font-bold tracking-widest">Light Frequency</span>
                    <span className="text-lg font-mono font-black text-cyan-400 drop-shadow-[0_0_8px_rgba(34,211,238,0.4)]">{sighting.front.lightFreq} Hz</span>
                  </div>
                  <div className="h-px bg-white/5"></div>
                  <div className="space-y-2">
                    <div className="flex justify-between text-[10px] text-gray-500 uppercase font-bold tracking-widest">
                      <span>Miriam's Womb (Progress)</span>
                      <span className="text-white">{sighting.front.gestation.toFixed(1)}%</span>
                    </div>
                    <div className="h-1.5 w-full bg-black rounded-full overflow-hidden border border-white/5">
                      <div 
                        className="h-full bg-gradient-to-r from-cyan-600 to-cyan-400 shadow-[0_0_10px_rgba(34,211,238,0.5)] transition-all duration-1000" 
                        style={{ width: `${sighting.front.gestation}%` }}
                      ></div>
                    </div>
                  </div>
                </div>
              </div>
            ) : (
              <div className="space-y-6">
                <div className="flex items-center gap-4">
                  <div className="h-px flex-1 bg-gradient-to-r from-transparent to-fuchsia-500/30"></div>
                  <span className="text-[10px] font-black text-fuchsia-500 uppercase tracking-[0.4em]">Mathematical Scale</span>
                  <div className="h-px flex-1 bg-gradient-to-l from-transparent to-fuchsia-500/30"></div>
                </div>

                <div className="grid grid-cols-2 gap-4">
                  <div className="bg-black border border-white/5 p-4 rounded-xl shadow-inner">
                    <span className="text-[9px] text-zinc-600 uppercase font-black block mb-2 tracking-widest">Shadow Tangent</span>
                    <span className="text-xl font-mono text-fuchsia-400 font-black">{sighting.back.shadowTangent.toFixed(4)}</span>
                  </div>
                  <div className="bg-black border border-white/5 p-4 rounded-xl shadow-inner">
                    <span className="text-[9px] text-zinc-600 uppercase font-black block mb-2 tracking-widest">Entropy Scale</span>
                    <span className="text-xl font-mono text-emerald-400 font-black">{sighting.back.waveEntropy.toFixed(4)}</span>
                  </div>
                </div>

                <div className="bg-zinc-950 border border-fuchsia-500/20 p-6 rounded-2xl space-y-5">
                   <div className="flex justify-between items-center">
                      <span className="text-[10px] text-gray-500 uppercase font-bold tracking-widest">Zodiac House</span>
                      <div className="flex items-center gap-2">
                         <span className="w-2 h-2 rounded-full bg-fuchsia-500 animate-pulse"></span>
                         <span className="text-xl font-mono font-black text-white">[{sighting.back.zodiacHouse}]</span>
                      </div>
                   </div>
                   <div className="h-px bg-white/5"></div>
                   <div className="flex justify-between items-center">
                      <span className="text-[10px] text-gray-500 uppercase font-bold tracking-widest">37:7 Barrier</span>
                      <span className={`text-[11px] font-black px-3 py-1 rounded border ${sighting.back.barrierStatus === 'LOCKED' ? 'bg-red-500/10 border-red-500/50 text-red-400 shadow-[0_0_10px_rgba(239,68,68,0.2)]' : 'bg-emerald-500/10 border-emerald-500/50 text-emerald-400'}`}>
                        {sighting.back.barrierStatus}
                      </span>
                   </div>
                   <div className="h-px bg-white/5"></div>
                   <div className="flex justify-between items-center">
                      <span className="text-[10px] text-gray-500 uppercase font-bold tracking-widest">Symmetry Check</span>
                      <span className={`font-mono text-sm ${sighting.back.symmetryViolation === 0 ? 'text-emerald-400' : 'text-amber-500'}`}>
                        {sighting.back.symmetryViolation === 0 ? 'Parity Intact' : 'Violation Detected'}
                      </span>
                   </div>
                </div>
              </div>
            )}

            <div className="pt-8 border-t border-white/5">
               <span className="text-[8px] text-gray-700 uppercase font-black tracking-widest block mb-2 px-1">Recursive Center Link (Isa Birth Index)</span>
               <div className="bg-black/80 border border-white/5 p-4 rounded-xl font-mono text-[10px] text-zinc-500 flex justify-between items-center">
                  <span>Distance to Pin:</span>
                  <span className="text-white font-black">{sighting.back.centerDist.toFixed(6)} μm</span>
               </div>
            </div>
          </div>
        )}
      </aside>

      {/* Main View: Interactive Mechanical Instrument */}
      <main className="flex-1 relative flex items-center justify-center p-4 lg:p-12">
        <div className="absolute inset-0 overflow-hidden pointer-events-none opacity-20">
            <div className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 w-[80%] aspect-square border border-white/5 rounded-full"></div>
            <div className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 w-[60%] aspect-square border border-white/5 rounded-full"></div>
            <div className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 w-[40%] aspect-square border border-white/5 rounded-full"></div>
        </div>

        <svg 
          ref={svgRef}
          viewBox="0 0 500 500" 
          className={`w-full h-full max-w-[85vh] transition-all duration-1000 ${activeSide === 'BACK' ? 'rotate-[180deg]' : ''}`}
        >
          {/* Mater (The Container) */}
          <circle cx={center} cy={center} r={outerRadius} fill="#05060a" stroke="#1c1d25" strokeWidth="15" className="shadow-2xl" />
          <circle cx={center} cy={center} r={outerRadius - 5} fill="none" stroke="#f59e0b" strokeWidth="0.5" opacity="0.3" />

          {/* Graduation Scales */}
          {Array.from({ length: 360 }).map((_, i) => {
            const angle = i;
            const isMajor = i % 10 === 0;
            const isQuarter = i % 90 === 0;
            const r1 = outerRadius - (isQuarter ? 15 : isMajor ? 10 : 5);
            const p1 = polarToCartesian(center, center, r1, angle);
            const p2 = polarToCartesian(center, center, outerRadius - 1, angle);
            return (
              <line key={i} x1={p1.x} y1={p1.y} x2={p2.x} y2={p2.y} stroke={isQuarter ? "#f59e0b" : "rgba(255,255,255,0.1)"} strokeWidth={isMajor ? 1.5 : 0.5} />
            );
          })}

          {activeSide === 'BACK' ? (
            <g opacity="0.4" transform="rotate(180 250 250)">
               <rect x={center - 120} y={center - 120} width="240" height="240" fill="none" stroke="rgba(217, 70, 239, 0.2)" strokeWidth="1" />
               {Array.from({ length: 12 }).map((_, i) => (
                 <React.Fragment key={i}>
                   <line x1={center - 120} y1={center - 120 + i*20} x2={center + 120} y2={center - 120 + i*20} stroke="rgba(255,255,255,0.05)" strokeWidth="0.5" />
                   <line x1={center - 120 + i*20} y1={center - 120} x2={center - 120 + i*20} y2={center + 120} stroke="rgba(255,255,255,0.05)" strokeWidth="0.5" />
                 </React.Fragment>
               ))}
            </g>
          ) : (
            <g opacity="0.3">
               <line x1={center} y1={center - outerRadius} x2={center} y2={center + outerRadius} stroke="rgba(34, 211, 238, 0.2)" strokeWidth="1" strokeDasharray="4 4" />
               <line x1={center - outerRadius} y1={center} x2={center + outerRadius} y2={center} stroke="rgba(34, 211, 238, 0.2)" strokeWidth="1" strokeDasharray="4 4" />
            </g>
          )}

          <g 
            transform={`rotate(${reteRotation} ${center} ${center})`}
            onPointerDown={(e) => handlePointerDown(e, 'rete')}
            className="cursor-grab active:cursor-grabbing transition-transform duration-[1200ms] cubic-bezier(0.34, 1.56, 0.64, 1)"
          >
             <circle cx={center} cy={center} r={innerRadius - 10} fill="none" stroke="rgba(34, 211, 238, 0.15)" strokeWidth="1.5" />
             <circle cx={center} cy={center + 35} r={85} fill="none" stroke="rgba(245, 158, 11, 0.1)" strokeWidth="2" />

             {CHAPTER_DETAILS.map((ch, i) => {
               if (i % 6 !== 0) return null;
               const angle = (i / 114) * 360;
               const r = innerRadius - 40 - (Math.sin(i) * 20);
               const p = polarToCartesian(center, center, r, angle);
               const isMuqattat = MUQATTAT_CHAPTERS.has(ch.number);
               return (
                 <g key={i}>
                   <path d={`M ${center} ${center} L ${p.x} ${p.y}`} stroke="rgba(255,255,255,0.05)" strokeWidth="0.5" />
                   <circle cx={p.x} cy={p.y} r={isMuqattat ? 3 : 1.5} fill={isMuqattat ? "#06b6d4" : "#444"} className={isMuqattat ? 'animate-pulse' : ''} />
                 </g>
               );
             })}
          </g>

          {sighting && (
            <g className="animate-in fade-in zoom-in duration-1000">
               {(() => {
                  const angle = (parseInt(sighting.front.coordinate.split(':')[0]) / 114) * 360;
                  const radius = (innerRadius * sighting.front.altitude) / 90;
                  const p = polarToCartesian(center, center, radius, angle);
                  return (
                    <g>
                       <circle cx={p.x} cy={p.y} r="12" fill="none" stroke={activeSide === 'FRONT' ? "#06b6d4" : "#d946ef"} strokeWidth="1" strokeDasharray="2 2" className="animate-[spin_10s_linear_infinite]" />
                       <circle cx={p.x} cy={p.y} r="4" fill={activeSide === 'FRONT' ? "#06b6d4" : "#d946ef"} className="shadow-[0_0_15px_currentColor]" />
                       <line x1={center} y1={center} x2={p.x} y2={p.y} stroke={activeSide === 'FRONT' ? "#06b6d4" : "#d946ef"} strokeWidth="0.5" strokeOpacity="0.5" />
                    </g>
                  );
               })()}
            </g>
          )}

          <g 
            transform={`rotate(${alidadeRotation} ${center} ${center})`}
            onPointerDown={(e) => handlePointerDown(e, 'alidade')}
            className={`cursor-grab active:cursor-grabbing ${!isDraggingAlidade ? 'transition-transform duration-[1200ms]' : ''}`}
            style={{ 
              transitionTimingFunction: 'cubic-bezier(0.34, 1.56, 0.64, 1)'
            }}
          >
            <rect x={center - 3.5} y={center - outerRadius - 10} width="7" height={(outerRadius + 10) * 2} fill="#2a2b35" rx="3.5" />
            <rect x={center - 1.5} y={center - outerRadius - 10} width="3" height={(outerRadius + 10) * 2} fill="#f59e0b" opacity="0.6" />

            <circle cx={center} cy={center - outerRadius + 10} r="4" fill="black" stroke="#f59e0b" strokeWidth="1" />
            <circle cx={center} cy={center + outerRadius - 10} r="4" fill="black" stroke="#f59e0b" strokeWidth="1" />

            <circle cx={center} cy={center} r={12} fill="#1a1b21" stroke="#f59e0b" strokeWidth="2" />
            <circle cx={center} cy={center} r={3} fill="#f59e0b" className="animate-pulse" />
          </g>
        </svg>

        <div className="absolute top-10 right-10 flex flex-col items-end pointer-events-none">
           <span className="text-cyan-400 font-black text-xl tracking-tighter uppercase italic">Phase Sync</span>
           <span className="text-gray-700 text-[10px] uppercase font-bold tracking-widest mt-1">Instrument Calibrated: 286-Horizon</span>
        </div>
      </main>
    </div>
  );
};

export default AstrolabeMode;

import React, { useState, useRef, useEffect, useMemo } from 'react';
import { TOTAL_SLICES, CHAPTER_DETAILS, MUQATTAT_CHAPTERS, BUBBLE_BLOCK_MAPPING_RAW } from '../constants.ts';
import { polarToCartesian } from '../utils.ts';
import { ShuffleIcon } from './Icons.tsx';

interface AstrolabeModeProps {
  onClose: () => void;
}

interface SightingData {
  front: {
    coordinate: string;
    lightFreq: string;
    zenithAngle: number;
    altitude: number;
    gestation: number; // 0-100%
  };
  back: {
    shadowTangent: number;
    shadowCotangent: number;
    waveEntropy: number;
    zodiacHouse: number;
    barrierStatus: 'OPEN' | 'LOCKED';
    centerDist: number;
    symmetryViolation: number; // 0 or 1
  };
}

const AstrolabeMode: React.FC<AstrolabeModeProps> = ({ onClose }) => {
  const [query, setQuery] = useState('12:100');
  const [sighting, setSighting] = useState<SightingData | null>(null);
  const [activeSide, setActiveSide] = useState<'FRONT' | 'BACK'>('FRONT');
  const [reteRotation, setReteRotation] = useState(0);
  const [alidadeRotation, setAlidadeRotation] = useState(0);
  const [isDraggingRete, setIsDraggingRete] = useState(false);
  const [isDraggingAlidade, setIsDraggingAlidade] = useState(false);

  const alidadeRotationRef = useRef(0);
  const svgRef = useRef<SVGSVGElement>(null);

  const HORIZON_LIMIT = 286;
  const PHI = 1.618;

  const calculateSighting = (coord: string): SightingData | null => {
    const parts = coord.split(':').map(Number);
    const C = parts[0];
    const V = parts[1] || 1;

    if (isNaN(C) || C < 1 || C > 114) return null;

    // FRONT SIDE CALCULATIONS
    const altitude = 90 - ((V / HORIZON_LIMIT) * 90);
    const azimuth = (C / 114) * 360;
    const zenithAngle = 90 - altitude;
    const isMuqattat = MUQATTAT_CHAPTERS.has(C);
    const lightFreq = isMuqattat ? (PHI * (C / 114)).toFixed(4) : "0.0000";
    const gestation = (V / HORIZON_LIMIT) * 100;

    // BACK SIDE CALCULATIONS
    const radAlt = (altitude * Math.PI) / 180;
    const shadowTangent = altitude === 0 ? 999.99 : Math.tan((90 - altitude) * Math.PI / 180);
    const shadowCotangent = altitude === 90 ? 0.00 : 1 / Math.tan(radAlt);

    const waveEntropy = Math.sin((azimuth * Math.PI) / 180);
    const zodiacHouse = Math.floor(((C - 12 + 114) % 114) / 9.5) + 1;
    const barrierStatus = altitude < 15 ? 'LOCKED' : 'OPEN';
    const centerDist = altitude / 90;
    const symmetryViolation = (C % 2 === V % 2) ? 0 : 1;

    return {
      front: {
        coordinate: `${C}:${V}`,
        lightFreq,
        zenithAngle,
        altitude,
        gestation
      },
      back: {
        shadowTangent,
        shadowCotangent,
        waveEntropy,
        zodiacHouse,
        barrierStatus,
        centerDist,
        symmetryViolation
      }
    };
  };

  const getShortestRotation = (current: number, target: number) => {
    const normalize = (angle: number) => ((angle % 360) + 360) % 360;
    const currNormalized = normalize(current);
    const targetNormalized = normalize(target);
    let diff = targetNormalized - currNormalized;

    if (diff > 180) diff -= 360;
    if (diff < -180) diff += 360;

    return current + diff;
  };

  const updateWithCoord = (coord: string) => {
    const result = calculateSighting(coord);
    if (result) {
      setSighting(result);
      const targetAzimuth = (parseInt(coord.split(':')[0]) / 114) * 360;
      const smoothRotation = getShortestRotation(alidadeRotationRef.current, targetAzimuth);

      alidadeRotationRef.current = smoothRotation;
      setAlidadeRotation(smoothRotation);
      setQuery(coord);
    }
  };

  useEffect(() => {
    updateWithCoord(query);
  }, []);

  const handleSearch = (e: React.FormEvent) => {
    e.preventDefault();
    updateWithCoord(query);
  };

  const handleRandom = () => {
    const randomSurah = Math.floor(Math.random() * 114) + 1;
    const maxAyahs = BUBBLE_BLOCK_MAPPING_RAW[randomSurah as keyof typeof BUBBLE_BLOCK_MAPPING_RAW] || 7;
    const randomAyah = Math.floor(Math.random() * maxAyahs) + 1;
    updateWithCoord(`${randomSurah}:${randomAyah}`);
  };

  const handleStep = (delta: number) => {
    const parts = query.split(':').map(Number);
    const C = parts[0];
    let V = parts[1] || 1;
    const maxAyahs = BUBBLE_BLOCK_MAPPING_RAW[C as keyof typeof BUBBLE_BLOCK_MAPPING_RAW] || 286;

    V += delta;
    if (V < 1) V = 1;
    if (V > maxAyahs) V = maxAyahs;

    updateWithCoord(`${C}:${V}`);
  };

  const getAngle = (clientX: number, clientY: number) => {
    if (!svgRef.current) return 0;
    const rect = svgRef.current.getBoundingClientRect();
    const centerX = rect.left + rect.width / 2;
    const centerY = rect.top + rect.height / 2;
    return Math.atan2(clientY - centerY, clientX - centerX) * (180 / Math.PI) + 90;
  };

  const handlePointerDown = (e: React.PointerEvent, target: 'rete' | 'alidade') => {
    e.stopPropagation();
    if (target === 'rete') setIsDraggingRete(true);
    else setIsDraggingAlidade(true);
  };

  useEffect(() => {
    const handlePointerMove = (e: PointerEvent) => {
      if (isDraggingRete) setReteRotation(getAngle(e.clientX, e.clientY));
      else if (isDraggingAlidade) {
        const angle = getAngle(e.clientX, e.clientY);
        setAlidadeRotation(angle);
        alidadeRotationRef.current = angle;
      }
    };
    const handlePointerUp = () => {
      setIsDraggingRete(false);
      setIsDraggingAlidade(false);
    };
    if (isDraggingRete || isDraggingAlidade) {
      window.addEventListener('pointermove', handlePointerMove);
      window.addEventListener('pointerup', handlePointerUp);
    }
    return () => {
      window.removeEventListener('pointermove', handlePointerMove);
      window.removeEventListener('pointerup', handlePointerUp);
    };
  }, [isDraggingRete, isDraggingAlidade]);

  const center = 250;
  const outerRadius = 240;
  const innerRadius = 220;

  const sightingIndicator = useMemo(() => {
      if (!sighting) return null;
      const angle = (parseInt(sighting.front.coordinate.split(':')[0]) / 114) * 360;
      const radius = (innerRadius * sighting.front.altitude) / 90;
      const p = polarToCartesian(center, center, radius, angle);
      return { p, angle, radius };
  }, [sighting, center, innerRadius]);

  return (
    <div className="fixed inset-0 z-[200] flex flex-col lg:flex-row bg-[#020306] animate-in fade-in zoom-in duration-500 overflow-hidden">
      {/* Sidebar: Mechanical Readout */}
      <aside className="w-full lg:w-[400px] bg-[#05060a]/90 backdrop-blur-3xl border-b lg:border-r border-cyan-950 p-8 flex flex-col gap-6 overflow-y-auto no-scrollbar shadow-[20px_0_40px_rgba(0,0,0,0.5)]">
        <div className="flex justify-between items-center border-b border-white/5 pb-4">
          <div>
            <h2 className="text-3xl font-black text-white tracking-tighter uppercase italic leading-none">MIZAN-114</h2>
            <p className="text-cyan-600 text-[10px] font-bold tracking-[0.4em] uppercase mt-2">Instrument of Dual Caustics</p>
          </div>
          <button onClick={onClose} className="p-3 rounded-full bg-white/5 text-gray-600 hover:text-white transition-colors border border-white/5 hover:border-white/20">
            <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6" fill="none" viewBox="0 0 24 24" stroke="currentColor">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M6 18L18 6M6 6l12 12" />
            </svg>
          </button>
        </div>

        <div className="flex gap-2 p-1 bg-black/40 rounded-xl border border-white/5 shadow-inner">
            <button 
              onClick={() => setActiveSide('FRONT')}
              className={`flex-1 py-2 text-[10px] font-black uppercase tracking-widest rounded-lg transition-all ${activeSide === 'FRONT' ? 'bg-cyan-600/20 text-cyan-400 border border-cyan-500/30' : 'text-gray-500 hover:text-gray-300'}`}
            >
              Side A: Celestial
            </button>
            <button 
              onClick={() => setActiveSide('BACK')}
              className={`flex-1 py-2 text-[10px] font-black uppercase tracking-widest rounded-lg transition-all ${activeSide === 'BACK' ? 'bg-fuchsia-600/20 text-fuchsia-400 border border-fuchsia-500/30' : 'text-gray-500 hover:text-gray-300'}`}
            >
              Side B: Math
            </button>
        </div>

        <div className="flex flex-col gap-3">
          <form onSubmit={handleSearch} className="relative group">
            <input 
              type="text" 
              value={query} 
              onChange={(e) => setQuery(e.target.value)}
              placeholder="[ C : V ]"
              className="w-full bg-black border border-white/10 rounded-xl px-6 py-4 text-cyan-400 font-mono text-xl focus:outline-none focus:border-cyan-500 transition-all placeholder:text-zinc-800 shadow-[inset_0_0_15px_rgba(0,0,0,1)]"
            />
            <button type="submit" className="absolute right-3 top-1/2 -translate-y-1/2 bg-cyan-600 hover:bg-cyan-500 text-black font-black px-4 py-2 rounded-lg transition-all uppercase text-[10px] tracking-widest shadow-xl active:scale-95">Sight</button>
          </form>

          <div className="flex gap-2 h-12">
            <button 
              onClick={() => handleStep(-1)}
              className="flex-1 bg-zinc-900 border border-white/5 hover:border-cyan-500/30 text-white rounded-xl font-black text-xl transition-all active:scale-95"
              title="Previous Verse"
            >
              -
            </button>
            <button 
              onClick={handleRandom}
              className="w-16 bg-zinc-900 border border-white/5 hover:border-cyan-500/30 text-cyan-400 flex items-center justify-center rounded-xl transition-all active:scale-95"
              title="Random Coordinate"
            >
              <ShuffleIcon />
            </button>
            <button 
              onClick={() => handleStep(1)}
              className="flex-1 bg-zinc-900 border border-white/5 hover:border-cyan-500/30 text-white rounded-xl font-black text-xl transition-all active:scale-95"
              title="Next Verse"
            >
              +
            </button>
          </div>
        </div>

        {sighting && (
          <div className="space-y-8 animate-in fade-in slide-in-from-bottom duration-1000">
            {activeSide === 'FRONT' ? (
              <div className="space-y-6">
                <div className="flex items-center gap-4">
                  <div className="h-px flex-1 bg-gradient-to-r from-transparent to-cyan-500/30"></div>
                  <span className="text-[10px] font-black text-cyan-500 uppercase tracking-[0.4em]">Celestial Alignment</span>
                  <div className="h-px flex-1 bg-gradient-to-l from-transparent to-cyan-500/30"></div>
                </div>

                <div className="grid grid-cols-2 gap-4">
                  <div className="bg-zinc-950 p-4 rounded-xl border border-white/5 flex flex-col">
                    <span className="text-[9px] text-gray-600 uppercase font-black tracking-widest mb-1">Vector Altitude</span>
                    <span className="text-2xl font-mono font-bold text-white leading-none">{sighting.front.altitude.toFixed(3)}°</span>
                  </div>
                  <div className="bg-zinc-950 p-4 rounded-xl border border-white/5 flex flex-col">
                    <span className="text-[9px] text-gray-600 uppercase font-black tracking-widest mb-1">Zenith Angle</span>
                    <span className="text-2xl font-mono font-bold text-white leading-none">{sighting.front.zenithAngle.toFixed(3)}°</span>
                  </div>
                </div>

                <div className="bg-cyan-950/10 border border-cyan-500/20 p-5 rounded-2xl space-y-4">
                  <div className="flex justify-between items-center group">
                    <span className="text-[10px] text-gray-500 uppercase font-bold tracking-widest">Light Frequency</span>
                    <span className="text-lg font-mono font-black text-cyan-400 drop-shadow-[0_0_8px_rgba(34,211,238,0.4)]">{sighting.front.lightFreq} Hz</span>
                  </div>
                  <div className="h-px bg-white/5"></div>
                  <div className="space-y-2">
                    <div className="flex justify-between text-[10px] text-gray-500 uppercase font-bold tracking-widest">
                      <span>Miriam's Womb (Progress)</span>
                      <span className="text-white">{sighting.front.gestation.toFixed(1)}%</span>
                    </div>
                    <div className="h-1.5 w-full bg-black rounded-full overflow-hidden border border-white/5">
                      <div 
                        className="h-full bg-gradient-to-r from-cyan-600 to-cyan-400 shadow-[0_0_10px_rgba(34,211,238,0.5)] transition-all duration-1000" 
                        style={{ width: `${sighting.front.gestation}%` }}
                      ></div>
                    </div>
                  </div>
                </div>
              </div>
            ) : (
              <div className="space-y-6">
                <div className="flex items-center gap-4">
                  <div className="h-px flex-1 bg-gradient-to-r from-transparent to-fuchsia-500/30"></div>
                  <span className="text-[10px] font-black text-fuchsia-500 uppercase tracking-[0.4em]">Mathematical Scale</span>
                  <div className="h-px flex-1 bg-gradient-to-l from-transparent to-fuchsia-500/30"></div>
                </div>

                <div className="grid grid-cols-2 gap-4">
                  <div className="bg-black border border-white/5 p-4 rounded-xl shadow-inner">
                    <span className="text-[9px] text-zinc-600 uppercase font-black block mb-2 tracking-widest">Shadow Tangent</span>
                    <span className="text-xl font-mono text-fuchsia-400 font-black">{sighting.back.shadowTangent.toFixed(4)}</span>
                  </div>
                  <div className="bg-black border border-white/5 p-4 rounded-xl shadow-inner">
                    <span className="text-[9px] text-zinc-600 uppercase font-black block mb-2 tracking-widest">Entropy Scale</span>
                    <span className="text-xl font-mono text-emerald-400 font-black">{sighting.back.waveEntropy.toFixed(4)}</span>
                  </div>
                </div>

                <div className="bg-zinc-950 border border-fuchsia-500/20 p-6 rounded-2xl space-y-5">
                   <div className="flex justify-between items-center">
                      <span className="text-[10px] text-gray-500 uppercase font-bold tracking-widest">Zodiac House</span>
                      <div className="flex items-center gap-2">
                         <span className="w-2 h-2 rounded-full bg-fuchsia-500 animate-pulse"></span>
                         <span className="text-xl font-mono font-black text-white">[{sighting.back.zodiacHouse}]</span>
                      </div>
                   </div>
                   <div className="h-px bg-white/5"></div>
                   <div className="flex justify-between items-center">
                      <span className="text-[10px] text-gray-500 uppercase font-bold tracking-widest">37:7 Barrier</span>
                      <span className={`text-[11px] font-black px-3 py-1 rounded border ${sighting.back.barrierStatus === 'LOCKED' ? 'bg-red-500/10 border-red-500/50 text-red-400 shadow-[0_0_10px_rgba(239,68,68,0.2)]' : 'bg-emerald-500/10 border-emerald-500/50 text-emerald-400'}`}>
                        {sighting.back.barrierStatus}
                      </span>
                   </div>
                   <div className="h-px bg-white/5"></div>
                   <div className="flex justify-between items-center">
                      <span className="text-[10px] text-gray-500 uppercase font-bold tracking-widest">Symmetry Check</span>
                      <span className={`font-mono text-sm ${sighting.back.symmetryViolation === 0 ? 'text-emerald-400' : 'text-amber-500'}`}>
                        {sighting.back.symmetryViolation === 0 ? 'Parity Intact' : 'Violation Detected'}
                      </span>
                   </div>
                </div>
              </div>
            )}

            <div className="pt-8 border-t border-white/5">
               <span className="text-[8px] text-gray-700 uppercase font-black tracking-widest block mb-2 px-1">Recursive Center Link (Isa Birth Index)</span>
               <div className="bg-black/80 border border-white/5 p-4 rounded-xl font-mono text-[10px] text-zinc-500 flex justify-between items-center">
                  <span>Distance to Pin:</span>
                  <span className="text-white font-black">{sighting.back.centerDist.toFixed(6)} μm</span>
               </div>
            </div>
          </div>
        )}
      </aside>

      {/* Main View: Interactive Mechanical Instrument */}
      <main className="flex-1 relative flex items-center justify-center p-4 lg:p-12">
        <div className="absolute inset-0 overflow-hidden pointer-events-none opacity-20">
            <div className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 w-[80%] aspect-square border border-white/5 rounded-full"></div>
            <div className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 w-[60%] aspect-square border border-white/5 rounded-full"></div>
            <div className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 w-[40%] aspect-square border border-white/5 rounded-full"></div>
        </div>

        <svg 
          ref={svgRef}
          viewBox="0 0 500 500" 
          className={`w-full h-full max-w-[85vh] transition-all duration-1000 ${activeSide === 'BACK' ? 'rotate-[180deg]' : ''}`}
        >
          {/* Mater (The Container) */}
          <circle cx={center} cy={center} r={outerRadius} fill="#05060a" stroke="#1c1d25" strokeWidth="15" className="shadow-2xl" />
          <circle cx={center} cy={center} r={outerRadius - 5} fill="none" stroke="#f59e0b" strokeWidth="0.5" opacity="0.3" />

          {/* Graduation Scales */}
          {Array.from({ length: 360 }).map((_, i) => {
            const angle = i;
            const isMajor = i % 10 === 0;
            const isQuarter = i % 90 === 0;
            const r1 = outerRadius - (isQuarter ? 15 : isMajor ? 10 : 5);
            const p1 = polarToCartesian(center, center, r1, angle);
            const p2 = polarToCartesian(center, center, outerRadius - 1, angle);
            return (
              <line key={i} x1={p1.x} y1={p1.y} x2={p2.x} y2={p2.y} stroke={isQuarter ? "#f59e0b" : "rgba(255,255,255,0.1)"} strokeWidth={isMajor ? 1.5 : 0.5} />
            );
          })}

          {activeSide === 'BACK' ? (
            <g opacity="0.4" transform="rotate(180 250 250)">
               <rect x={center - 120} y={center - 120} width="240" height="240" fill="none" stroke="rgba(217, 70, 239, 0.2)" strokeWidth="1" />
               {Array.from({ length: 12 }).map((_, i) => (
                 <React.Fragment key={i}>
                   <line x1={center - 120} y1={center - 120 + i*20} x2={center + 120} y2={center - 120 + i*20} stroke="rgba(255,255,255,0.05)" strokeWidth="0.5" />
                   <line x1={center - 120 + i*20} y1={center - 120} x2={center - 120 + i*20} y2={center + 120} stroke="rgba(255,255,255,0.05)" strokeWidth="0.5" />
                 </React.Fragment>
               ))}
            </g>
          ) : (
            <g opacity="0.3">
               <line x1={center} y1={center - outerRadius} x2={center} y2={center + outerRadius} stroke="rgba(34, 211, 238, 0.2)" strokeWidth="1" strokeDasharray="4 4" />
               <line x1={center - outerRadius} y1={center} x2={center + outerRadius} y2={center} stroke="rgba(34, 211, 238, 0.2)" strokeWidth="1" strokeDasharray="4 4" />
            </g>
          )}

          <g 
            transform={`rotate(${reteRotation} ${center} ${center})`}
            onPointerDown={(e) => handlePointerDown(e, 'rete')}
            className={`cursor-grab active:cursor-grabbing ${!isDraggingRete ? 'transition-transform duration-[1200ms]' : ''}`}
            style={{ transitionTimingFunction: 'cubic-bezier(0.19, 1, 0.22, 1)' }}
          >
             <circle cx={center} cy={center} r={innerRadius - 10} fill="none" stroke="rgba(34, 211, 238, 0.15)" strokeWidth="1.5" />
             <circle cx={center} cy={center + 35} r={85} fill="none" stroke="rgba(245, 158, 11, 0.1)" strokeWidth="2" />

             {CHAPTER_DETAILS.map((ch, i) => {
               if (i % 6 !== 0) return null;
               const angle = (i / 114) * 360;
               const r = innerRadius - 40 - (Math.sin(i) * 20);
               const p = polarToCartesian(center, center, r, angle);
               const isMuqattat = MUQATTAT_CHAPTERS.has(ch.number);
               return (
                 <g key={i}>
                   <path d={`M ${center} ${center} L ${p.x} ${p.y}`} stroke="rgba(255,255,255,0.05)" strokeWidth="0.5" />
                   <circle cx={p.x} cy={p.y} r={isMuqattat ? 3 : 1.5} fill={isMuqattat ? "#06b6d4" : "#444"} className={isMuqattat ? 'animate-pulse' : ''} />
                 </g>
               );
             })}
          </g>

          {/* Sighting Indicator with Gliding Transform */}
          {sightingIndicator && (
            <g 
                style={{ 
                    transition: 'transform 0.8s cubic-bezier(0.19, 1, 0.22, 1)',
                    transform: `translate(${sightingIndicator.p.x - center}px, ${sightingIndicator.p.y - center}px)`
                }}
                transform={`translate(${center} ${center})`}
            >
               <g className="animate-in fade-in zoom-in duration-1000">
                   <circle cx={0} cy={0} r="12" fill="none" stroke={activeSide === 'FRONT' ? "#06b6d4" : "#d946ef"} strokeWidth="1" strokeDasharray="2 2" className="animate-[spin_10s_linear_infinite]" />
                   <circle cx={0} cy={0} r="4" fill={activeSide === 'FRONT' ? "#06b6d4" : "#d946ef"} className="shadow-[0_0_15px_currentColor]" />
                   <line x1={-sightingIndicator.p.x + center} y1={-sightingIndicator.p.y + center} x2={0} y2={0} stroke={activeSide === 'FRONT' ? "#06b6d4" : "#d946ef"} strokeWidth="0.5" strokeOpacity="0.5" />
               </g>
            </g>
          )}

          <g 
            transform={`rotate(${alidadeRotation} ${center} ${center})`}
            onPointerDown={(e) => handlePointerDown(e, 'alidade')}
            className={`cursor-grab active:cursor-grabbing ${!isDraggingAlidade ? 'transition-transform duration-[800ms]' : ''}`}
            style={{ 
              transitionTimingFunction: 'cubic-bezier(0.19, 1, 0.22, 1)'
            }}
          >
            <rect x={center - 3.5} y={center - outerRadius - 10} width="7" height={(outerRadius + 10) * 2} fill="#2a2b35" rx="3.5" />
            <rect x={center - 1.5} y={center - outerRadius - 10} width="3" height={(outerRadius + 10) * 2} fill="#f59e0b" opacity="0.6" />

            <circle cx={center} cy={center - outerRadius + 10} r="4" fill="black" stroke="#f59e0b" strokeWidth="1" />
            <circle cx={center} cy={center + outerRadius - 10} r="4" fill="black" stroke="#f59e0b" strokeWidth="1" />

            <circle cx={center} cy={center} r={12} fill="#1a1b21" stroke="#f59e0b" strokeWidth="2" />
            <circle cx={center} cy={center} r={3} fill="#f59e0b" className="animate-pulse" />
          </g>
        </svg>

        <div className="absolute top-10 right-10 flex flex-col items-end pointer-events-none">
           <span className="text-cyan-400 font-black text-xl tracking-tighter uppercase italic">Phase Sync</span>
           <span className="text-gray-700 text-[10px] uppercase font-bold tracking-widest mt-1">Instrument Calibrated: 286-Horizon</span>
        </div>
      </main>
    </div>
  );
};

export default AstrolabeMode;

import React, { useState, useRef, useEffect, useMemo } from 'react';
import { TOTAL_SLICES, CHAPTER_DETAILS, MUQATTAT_CHAPTERS, BUBBLE_BLOCK_MAPPING_RAW } from '../constants.ts';
import { polarToCartesian } from '../utils.ts';
import { ShuffleIcon } from './Icons.tsx';

interface AstrolabeModeProps {
  onClose: () => void;
}

interface SightingData {
  front: {
    coordinate: string;
    lightFreq: string;
    zenithAngle: number;
    altitude: number;
    gestation: number;
    symbol: '◎' | '✦';
    sweepDelta: number;
  };
  back: {
    umbraRecta: number;   // tan(alt)
    umbraVersa: number;   // cot(alt)
    mizanConstant: number; // (C*V)/(114*286)
    zodiacHouse: number;
    barrierStatus: 'OPEN' | 'LOCKED';
    centerDist: number;
  };
}

const AstrolabeMode: React.FC<AstrolabeModeProps> = ({ onClose }) => {
  const [query, setQuery] = useState('12:100');
  const [sighting, setSighting] = useState<SightingData | null>(null);
  const [activeSide, setActiveSide] = useState<'FRONT' | 'BACK'>('FRONT');
  const [reteRotation, setReteRotation] = useState(0);
  const [alidadeRotation, setAlidadeRotation] = useState(0);
  const [isDraggingRete, setIsDraggingRete] = useState(false);
  const [isDraggingAlidade, setIsDraggingAlidade] = useState(false);

  const alidadeRotationRef = useRef(0);
  const svgRef = useRef<SVGSVGElement>(null);

  const HORIZON_LIMIT = 286;
  const PHI = 1.618;

  const calculateSighting = (coord: string): SightingData | null => {
    const parts = coord.split(':').map(Number);
    const C = parts[0];
    const V = parts[1] || 1;

    if (isNaN(C) || C < 1 || C > 114) return null;

    // FRONT SIDE CALCULATIONS
    const altitude = 90 - ((V / HORIZON_LIMIT) * 90);
    const azimuth = (C / 114) * 360;
    const zenithAngle = 90 - altitude;
    const isMuqattat = MUQATTAT_CHAPTERS.has(C);
    const lightFreq = isMuqattat ? (PHI * (C / 114)).toFixed(4) : "0.0000";
    const gestation = (V / HORIZON_LIMIT) * 100;

    // Rotational Delta Logic
    const targetAzimuth = (C / 114) * 360;
    const sweepDelta = targetAzimuth - (alidadeRotationRef.current % 360);

    // BACK SIDE CALCULATIONS
    const radAlt = (altitude * Math.PI) / 180;
    const radZenith = ((90 - altitude) * Math.PI) / 180;

    // Umbra Recta (Shadow on Vertical) / Umbra Versa (Shadow on Horizontal)
    const umbraRecta = altitude === 0 ? 99.9 : Math.tan(radZenith);
    const umbraVersa = altitude === 90 ? 0.0 : 1 / Math.tan(radAlt);

    // Mizan Constant: M = (C*V) / (114*286)
    const mizanConstant = (C * V) / (114 * 286);

    const zodiacHouse = Math.floor(((C - 12 + 114) % 114) / 9.5) + 1;
    const barrierStatus = altitude < 15 ? 'LOCKED' : 'OPEN';
    const centerDist = altitude / 90;

    return {
      front: {
        coordinate: `${C}:${V}`,
        lightFreq,
        zenithAngle,
        altitude,
        gestation,
        symbol: isMuqattat ? '✦' : '◎',
        sweepDelta
      },
      back: {
        umbraRecta,
        umbraVersa,
        mizanConstant,
        zodiacHouse,
        barrierStatus,
        centerDist,
      }
    };
  };

  const getShortestRotation = (current: number, target: number) => {
    const normalize = (angle: number) => ((angle % 360) + 360) % 360;
    const currNormalized = normalize(current);
    const targetNormalized = normalize(target);
    let diff = targetNormalized - currNormalized;

    if (diff > 180) diff -= 360;
    if (diff < -180) diff += 360;

    return current + diff;
  };

  const updateWithCoord = (coord: string) => {
    const result = calculateSighting(coord);
    if (result) {
      setSighting(result);
      const targetAzimuth = (parseInt(coord.split(':')[0]) / 114) * 360;
      const smoothRotation = getShortestRotation(alidadeRotationRef.current, targetAzimuth);

      alidadeRotationRef.current = smoothRotation;
      setAlidadeRotation(smoothRotation);
      setQuery(coord);
    }
  };

  useEffect(() => {
    updateWithCoord(query);
  }, []);

  const handleSearch = (e: React.FormEvent) => {
    e.preventDefault();
    updateWithCoord(query);
  };

  const handleRandom = () => {
    const randomSurah = Math.floor(Math.random() * 114) + 1;
    const maxAyahs = BUBBLE_BLOCK_MAPPING_RAW[randomSurah as keyof typeof BUBBLE_BLOCK_MAPPING_RAW] || 7;
    const randomAyah = Math.floor(Math.random() * maxAyahs) + 1;
    updateWithCoord(`${randomSurah}:${randomAyah}`);
  };

  const handleStep = (delta: number) => {
    const parts = query.split(':').map(Number);
    const C = parts[0];
    let V = parts[1] || 1;
    const maxAyahs = BUBBLE_BLOCK_MAPPING_RAW[C as keyof typeof BUBBLE_BLOCK_MAPPING_RAW] || 286;

    V += delta;
    if (V < 1) V = 1;
    if (V > maxAyahs) V = maxAyahs;

    updateWithCoord(`${C}:${V}`);
  };

  const getAngle = (clientX: number, clientY: number) => {
    if (!svgRef.current) return 0;
    const rect = svgRef.current.getBoundingClientRect();
    const centerX = rect.left + rect.width / 2;
    const centerY = rect.top + rect.height / 2;
    return Math.atan2(clientY - centerY, clientX - centerX) * (180 / Math.PI) + 90;
  };

  const handlePointerDown = (e: React.PointerEvent, target: 'rete' | 'alidade') => {
    e.stopPropagation();
    if (target === 'rete') setIsDraggingRete(true);
    else setIsDraggingAlidade(true);
  };

  useEffect(() => {
    const handlePointerMove = (e: PointerEvent) => {
      if (isDraggingRete) setReteRotation(getAngle(e.clientX, e.clientY));
      else if (isDraggingAlidade) {
        const angle = getAngle(e.clientX, e.clientY);
        setAlidadeRotation(angle);
        alidadeRotationRef.current = angle;
      }
    };
    const handlePointerUp = () => {
      setIsDraggingRete(false);
      setIsDraggingAlidade(false);
    };
    if (isDraggingRete || isDraggingAlidade) {
      window.addEventListener('pointermove', handlePointerMove);
      window.addEventListener('pointerup', handlePointerUp);
    }
    return () => {
      window.removeEventListener('pointermove', handlePointerMove);
      window.removeEventListener('pointerup', handlePointerUp);
    };
  }, [isDraggingRete, isDraggingAlidade]);

  const center = 250;
  const outerRadius = 240;
  const innerRadius = 220;

  const sightingIndicator = useMemo(() => {
      if (!sighting) return null;
      const angle = (parseInt(sighting.front.coordinate.split(':')[0]) / 114) * 360;
      const radius = (innerRadius * sighting.front.altitude) / 90;
      const p = polarToCartesian(center, center, radius, angle);
      return { p, angle, radius };
  }, [sighting, center, innerRadius]);

  return (
    <div className="fixed inset-0 z-[200] flex flex-col lg:flex-row bg-[#020306] animate-in fade-in zoom-in duration-500 overflow-hidden font-sans">
      {/* Sidebar: Mechanical Visual Dashboard */}
      <aside className="w-full lg:w-[420px] bg-[#05060a]/95 backdrop-blur-3xl border-b lg:border-r border-cyan-950 p-8 flex flex-col gap-6 overflow-y-auto no-scrollbar shadow-2xl relative">
        {/* Dashboard Frame Symbols */}
        <div className="absolute top-4 left-4 text-[10px] text-cyan-800 font-mono">🜄 WATER</div>
        <div className="absolute top-4 right-4 text-[10px] text-amber-800 font-mono">🜂 FIRE</div>
        <div className="absolute bottom-4 left-4 text-[10px] text-white/20 font-mono">🜁 LIGHT</div>
        <div className="absolute bottom-4 right-4 text-[10px] text-red-900 font-mono">🕳 ABYSS</div>

        <div className="flex justify-between items-center border-b border-white/5 pb-4">
          <div>
            <h2 className="text-3xl font-black text-white tracking-tighter uppercase italic leading-none">MIZAN-114</h2>
            <p className="text-cyan-700 text-[9px] font-bold tracking-[0.5em] uppercase mt-2 italic">Celestial Kinematics Engine</p>
          </div>
          <button onClick={onClose} className="p-2 rounded-xl bg-white/5 text-gray-600 hover:text-white transition-all border border-white/5">
            <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6" fill="none" viewBox="0 0 24 24" stroke="currentColor">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M6 18L18 6M6 6l12 12" />
            </svg>
          </button>
        </div>

        <div className="flex gap-1 p-1 bg-black/60 rounded-xl border border-white/5">
            <button onClick={() => setActiveSide('FRONT')} className={`flex-1 py-2 text-[10px] font-black uppercase tracking-widest rounded-lg transition-all ${activeSide === 'FRONT' ? 'bg-cyan-600/20 text-cyan-400 border border-cyan-500/20' : 'text-zinc-600 hover:text-zinc-400'}`}>Side A: Celestial</button>
            <button onClick={() => setActiveSide('BACK')} className={`flex-1 py-2 text-[10px] font-black uppercase tracking-widest rounded-lg transition-all ${activeSide === 'BACK' ? 'bg-amber-600/20 text-amber-400 border border-amber-500/20' : 'text-zinc-600 hover:text-zinc-400'}`}>Side B: Mathematical</button>
        </div>

        <div className="flex flex-col gap-3">
          <form onSubmit={handleSearch} className="relative group">
            <input type="text" value={query} onChange={(e) => setQuery(e.target.value)} placeholder="[ C : V ]" className="w-full bg-black border border-white/10 rounded-xl px-6 py-4 text-cyan-400 font-mono text-xl focus:outline-none focus:border-cyan-500 transition-all placeholder:text-zinc-800 shadow-[inset_0_0_15px_rgba(0,0,0,1)]" />
            <button type="submit" className="absolute right-3 top-1/2 -translate-y-1/2 bg-cyan-600 hover:bg-cyan-500 text-black font-black px-4 py-2 rounded-lg transition-all uppercase text-[10px] tracking-widest">Sight</button>
          </form>
          <div className="flex gap-2 h-12">
            <button onClick={() => handleStep(-1)} className="flex-1 bg-zinc-900/50 border border-white/5 hover:border-cyan-500/30 text-white rounded-xl font-black text-xl transition-all shadow-md">-</button>
            <button onClick={handleRandom} className="w-16 bg-zinc-900/50 border border-white/5 hover:border-cyan-500/30 text-cyan-400 flex items-center justify-center rounded-xl transition-all shadow-md"><ShuffleIcon /></button>
            <button onClick={() => handleStep(1)} className="flex-1 bg-zinc-900/50 border border-white/5 hover:border-cyan-500/30 text-white rounded-xl font-black text-xl transition-all shadow-md">+</button>
          </div>
        </div>

        {sighting && (
          <div className="space-y-6 animate-in fade-in slide-in-from-bottom duration-700">
            {activeSide === 'FRONT' ? (
              <div className="space-y-4">
                <div className="bg-black/80 border border-cyan-500/10 p-5 rounded-2xl relative overflow-hidden group">
                  <div className="absolute top-0 left-0 w-1 h-full bg-cyan-600 opacity-40"></div>
                  <div className="flex justify-between items-center mb-4">
                    <span className="text-[10px] font-black text-cyan-600 uppercase tracking-widest">Vector Alignment</span>
                    <span className="text-lg font-mono text-white">{sighting.front.symbol} {sighting.front.coordinate}</span>
                  </div>
                  <div className="grid grid-cols-2 gap-4 mb-4">
                    <div>
                      <label className="text-[8px] text-zinc-500 uppercase block mb-1">R (Radius)</label>
                      <span className="text-xl font-mono text-cyan-100">{(sighting.front.altitude / 90).toFixed(4)}</span>
                    </div>
                    <div>
                      <label className="text-[8px] text-zinc-500 uppercase block mb-1">Θ (Theta)</label>
                      <span className="text-xl font-mono text-cyan-100">{(parseInt(sighting.front.coordinate.split(':')[0]) / 114 * 360).toFixed(2)}°</span>
                    </div>
                  </div>
                  <div className="bg-white/5 p-3 rounded-lg border border-white/5">
                    <p className="text-[9px] text-zinc-400 italic">"The Alidade sweeps <span className="text-cyan-400 font-bold">{Math.abs(sighting.front.sweepDelta).toFixed(1)}°</span> {sighting.front.sweepDelta >= 0 ? 'clockwise' : 'counter-clockwise'} to align at Altitude <span className="text-cyan-400 font-bold">{sighting.front.altitude.toFixed(2)}°</span>."</p>
                  </div>
                </div>

                <div className="grid grid-cols-2 gap-3">
                  <div className="bg-zinc-950 p-4 rounded-xl border border-white/5">
                    <span className="text-[9px] text-zinc-600 uppercase font-black block mb-1 tracking-widest">Light Freq</span>
                    <span className="text-lg font-mono font-bold text-white leading-none">{sighting.front.lightFreq} Hz</span>
                  </div>
                  <div className="bg-zinc-950 p-4 rounded-xl border border-white/5">
                    <span className="text-[9px] text-zinc-600 uppercase font-black block mb-1 tracking-widest">Womb Progress</span>
                    <span className="text-lg font-mono font-bold text-cyan-400 leading-none">{sighting.front.gestation.toFixed(1)}%</span>
                  </div>
                </div>
              </div>
            ) : (
              <div className="space-y-4">
                <div className="bg-black/80 border border-amber-500/10 p-5 rounded-2xl relative overflow-hidden group">
                  <div className="absolute top-0 left-0 w-1 h-full bg-amber-600 opacity-40"></div>
                  <div className="flex justify-between items-center mb-4">
                    <span className="text-[10px] font-black text-amber-600 uppercase tracking-widest">Mathematical Constants</span>
                    <span className="text-[10px] font-mono text-amber-400">M = {sighting.back.mizanConstant.toFixed(8)}</span>
                  </div>
                  <div className="grid grid-cols-2 gap-4">
                    <div className="bg-amber-950/10 p-3 rounded-lg border border-amber-500/10">
                      <label className="text-[8px] text-zinc-500 uppercase block mb-1">Umbra Recta (V-Shadow)</label>
                      <span className="text-lg font-mono text-amber-100">{sighting.back.umbraRecta.toFixed(4)}</span>
                    </div>
                    <div className="bg-amber-950/10 p-3 rounded-lg border border-amber-500/10">
                      <label className="text-[8px] text-zinc-500 uppercase block mb-1">Umbra Versa (H-Shadow)</label>
                      <span className="text-lg font-mono text-amber-100">{sighting.back.umbraVersa.toFixed(4)}</span>
                    </div>
                  </div>
                </div>

                <div className="bg-zinc-950 border border-amber-500/10 p-5 rounded-2xl space-y-4">
                  <div className="flex justify-between items-center text-[10px]">
                    <span className="text-zinc-500 uppercase font-bold tracking-widest">37:7 Barrier</span>
                    <span className={`font-black px-3 py-1 rounded border ${sighting.back.barrierStatus === 'LOCKED' ? 'bg-red-500/10 border-red-500/50 text-red-400' : 'bg-emerald-500/10 border-emerald-500/50 text-emerald-400'}`}>{sighting.back.barrierStatus}</span>
                  </div>
                  <div className="h-px bg-white/5"></div>
                  <div className="flex justify-between items-center">
                    <span className="text-[10px] text-zinc-500 uppercase font-bold tracking-widest">Manzil Index</span>
                    <span className="text-xl font-mono font-black text-white">[{Math.ceil(sighting.back.zodiacHouse / 1.714)}]</span>
                  </div>
                </div>
              </div>
            )}

            <div className="pt-4 border-t border-white/5">
               <span className="text-[8px] text-zinc-700 uppercase font-black tracking-widest block mb-2">Recursive Pin Link (Distance to Origin)</span>
               <div className="bg-black/40 border border-white/5 p-4 rounded-xl font-mono text-[11px] text-zinc-500 flex justify-between items-center shadow-inner">
                  <span>Center Pin Offset:</span>
                  <span className="text-white font-black">{sighting.back.centerDist.toFixed(7)} units</span>
               </div>
            </div>
          </div>
        )}
      </aside>

      {/* Main View: Interactive Mechanical Instrument */}
      <main className="flex-1 relative flex items-center justify-center p-4 lg:p-12">
        <div className="absolute inset-0 overflow-hidden pointer-events-none opacity-20">
            <div className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 w-[90%] aspect-square border border-white/5 rounded-full"></div>
            <div className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 w-[70%] aspect-square border border-white/5 rounded-full"></div>
        </div>

        <svg ref={svgRef} viewBox="0 0 500 500" className={`w-full h-full max-w-[85vh] transition-all duration-[1500ms] ${activeSide === 'BACK' ? 'rotate-[180deg]' : ''}`}>
          {/* Mater (Limbus Frame) */}
          <circle cx={center} cy={center} r={outerRadius} fill="#05060a" stroke="#1c1d25" strokeWidth="18" className="shadow-2xl" />
          <circle cx={center} cy={center} r={outerRadius - 8} fill="none" stroke="#f59e0b" strokeWidth="0.5" opacity="0.3" />

          {/* Limbus Graduation (360° / 114 Surahs) */}
          {Array.from({ length: 360 }).map((_, i) => {
            const angle = i;
            const isMajor = i % 10 === 0;
            const isChapter = i % (360/114) === 0; // Approx
            const r1 = outerRadius - (isMajor ? 14 : 7);
            const p1 = polarToCartesian(center, center, r1, angle);
            const p2 = polarToCartesian(center, center, outerRadius - 1, angle);
            return (
              <line key={i} x1={p1.x} y1={p1.y} x2={p2.x} y2={p2.y} stroke={isMajor ? "#f59e0b" : "rgba(255,255,255,0.1)"} strokeWidth={isMajor ? 1.5 : 0.5} />
            );
          })}

          {/* Almucantars (10 Concentric Circles representing 286 Verses) */}
          {Array.from({ length: 10 }).map((_, i) => (
            <circle key={i} cx={center} cy={center} r={(innerRadius / 10) * (i + 1)} fill="none" stroke="rgba(34, 211, 238, 0.05)" strokeWidth="0.5" />
          ))}

          {activeSide === 'BACK' ? (
            <g opacity="0.4" transform="rotate(180 250 250)">
               {/* Shadow Square */}
               <rect x={center - 110} y={center - 110} width="220" height="220" fill="none" stroke="rgba(245, 158, 11, 0.3)" strokeWidth="1.5" />
               {Array.from({ length: 11 }).map((_, i) => (
                 <React.Fragment key={i}>
                   <line x1={center - 110} y1={center - 110 + i*20} x2={center + 110} y2={center - 110 + i*20} stroke="rgba(255,255,255,0.08)" strokeWidth="0.5" />
                   <line x1={center - 110 + i*20} y1={center - 110} x2={center - 110 + i*20} y2={center + 110} stroke="rgba(255,255,255,0.08)" strokeWidth="0.5" />
                 </React.Fragment>
               ))}
            </g>
          ) : (
            <g opacity="0.3">
               <line x1={center} y1={center - outerRadius} x2={center} y2={center + outerRadius} stroke="rgba(34, 211, 238, 0.3)" strokeWidth="1" strokeDasharray="4 4" />
               <line x1={center - outerRadius} y1={center} x2={center + outerRadius} y2={center} stroke="rgba(34, 211, 238, 0.3)" strokeWidth="1" strokeDasharray="4 4" />
               {/* Quadrant Labels */}
               <text x={center + 120} y={center - 120} fill="#06b6d4" fontSize="8" fontWeight="black" textAnchor="middle">EXPANSION (LIGHT)</text>
               <text x={center + 120} y={center + 120} fill="#06b6d4" fontSize="8" fontWeight="black" textAnchor="middle">KINGDOM (MATTER)</text>
               <text x={center - 120} y={center + 120} fill="#06b6d4" fontSize="8" fontWeight="black" textAnchor="middle">DECAY (SHADOW)</text>
               <text x={center - 120} y={center - 120} fill="#06b6d4" fontSize="8" fontWeight="black" textAnchor="middle">ABYSS (RETURN)</text>
            </g>
          )}

          {/* Rete (Celestial Web) */}
          <g transform={`rotate(${reteRotation} ${center} ${center})`} onPointerDown={(e) => handlePointerDown(e, 'rete')} className={`cursor-grab active:cursor-grabbing ${!isDraggingRete ? 'transition-transform duration-[1500ms]' : ''}`} style={{ transitionTimingFunction: 'cubic-bezier(0.19, 1, 0.22, 1)' }}>
             <circle cx={center} cy={center} r={innerRadius - 5} fill="none" stroke="rgba(34, 211, 238, 0.15)" strokeWidth="1.2" />
             <circle cx={center} cy={center + 30} r={95} fill="none" stroke="rgba(245, 158, 11, 0.1)" strokeWidth="2" />
             {Array.from(MUQATTAT_CHAPTERS).map((chId, i) => {
               const angle = (chId / 114) * 360;
               const r = innerRadius - 30 - (i % 5 * 10);
               const p = polarToCartesian(center, center, r, angle);
               return (
                 <g key={chId}>
                   <path d={`M ${center} ${center} L ${p.x} ${p.y}`} stroke="rgba(255,255,255,0.04)" strokeWidth="0.5" />
                   <text x={p.x} y={p.y} textAnchor="middle" dominantBaseline="middle" fill="#06b6d4" fontSize="12" className="animate-pulse select-none" style={{ filter: 'drop-shadow(0 0 5px #06b6d4)' }}>✦</text>
                 </g>
               );
             })}
          </g>

          {/* Sighting Indicator (◎) */}
          {sightingIndicator && (
            <g style={{ transition: 'transform 0.8s cubic-bezier(0.19, 1, 0.22, 1)', transform: `translate(${sightingIndicator.p.x - center}px, ${sightingIndicator.p.y - center}px)` }} transform={`translate(${center} ${center})`}>
               <g className="animate-in fade-in zoom-in duration-1000">
                   <circle cx={0} cy={0} r="14" fill="none" stroke={activeSide === 'FRONT' ? "#06b6d4" : "#f59e0b"} strokeWidth="1" strokeDasharray="2 2" className="animate-[spin_12s_linear_infinite]" />
                   <text x={0} y={0} textAnchor="middle" dominantBaseline="middle" fill={activeSide === 'FRONT' ? "#06b6d4" : "#f59e0b"} fontSize="14" className="font-bold select-none">{sighting?.front.symbol}</text>
                   <line x1={-sightingIndicator.p.x + center} y1={-sightingIndicator.p.y + center} x2={0} y2={0} stroke={activeSide === 'FRONT' ? "#06b6d4" : "#f59e0b"} strokeWidth="0.5" strokeOpacity="0.4" />
               </g>
            </g>
          )}

          {/* Alidade (Mechanical Sighting Ruler) */}
          <g transform={`rotate(${alidadeRotation} ${center} ${center})`} onPointerDown={(e) => handlePointerDown(e, 'alidade')} className={`cursor-grab active:cursor-grabbing ${!isDraggingAlidade ? 'transition-transform duration-[1200ms]' : ''}`} style={{ transitionTimingFunction: 'cubic-bezier(0.19, 1, 0.22, 1)' }}>
            <rect x={center - 4} y={center - outerRadius - 10} width="8" height={(outerRadius + 10) * 2} fill="#24252d" rx="4" className="shadow-lg" />
            <rect x={center - 1} y={center - outerRadius - 10} width="2" height={(outerRadius + 10) * 2} fill="#f59e0b" opacity="0.4" />
            <circle cx={center} cy={center - outerRadius + 8} r="5" fill="black" stroke="#f59e0b" strokeWidth="1.5" />
            <circle cx={center} cy={center + outerRadius - 8} r="5" fill="black" stroke="#f59e0b" strokeWidth="1.5" />
            <circle cx={center} cy={center} r={14} fill="#1a1b21" stroke="#f59e0b" strokeWidth="2.5" />
            <circle cx={center} cy={center} r={4} fill="#f59e0b" className="animate-pulse" />
          </g>
        </svg>

        <div className="absolute top-10 right-10 flex flex-col items-end pointer-events-none">
           <span className="text-cyan-400 font-black text-2xl tracking-tighter uppercase italic drop-shadow-[0_0_10px_rgba(6,182,212,0.4)]">Phase Sync</span>
           <span className="text-zinc-700 text-[10px] uppercase font-bold tracking-widest mt-1">286-HORIZON • CALIBRATED</span>
        </div>
      </main>
    </div>
  );
};

export default AstrolabeMode;

import React, { useState, useRef, useEffect, useMemo } from 'react';
import { TOTAL_SLICES, CHAPTER_DETAILS, MUQATTAT_CHAPTERS, BUBBLE_BLOCK_MAPPING_RAW } from '../constants.ts';
import { polarToCartesian } from '../utils.ts';
import { ShuffleIcon } from './Icons.tsx';

interface AstrolabeModeProps {
  onClose: () => void;
}

interface SightingData {
  front: {
    coordinate: string;
    lightFreq: string;
    theta: number;
    radius: number;
    altitude: number;
    symbol: '◎' | '✦';
    sweepDelta: number;
    sweepDirection: 'clockwise' | 'counter-clockwise';
    isPrime: boolean;
  };
  back: {
    umbraRecta: number;   // tan(zenith)
    umbraVersa: number;   // cot(alt)
    mizanConstant: number; // (C*V)/(114*286)
    manzil: number;
    entropy: number;
  };
}

const AstrolabeMode: React.FC<AstrolabeModeProps> = ({ onClose }) => {
  const [query, setQuery] = useState('12:100');
  const [sighting, setSighting] = useState<SightingData | null>(null);
  const [activeSide, setActiveSide] = useState<'FRONT' | 'BACK'>('FRONT');
  const [reteRotation, setReteRotation] = useState(0);
  const [alidadeRotation, setAlidadeRotation] = useState(0);
  const [isDraggingRete, setIsDraggingRete] = useState(false);
  const [isDraggingAlidade, setIsDraggingAlidade] = useState(false);

  const alidadeRotationRef = useRef(0);
  const svgRef = useRef<SVGSVGElement>(null);

  const HORIZON_LIMIT = 286;
  const PHI = 1.618;

  const isPrime = (num: number) => {
    for(let i = 2, s = Math.sqrt(num); i <= s; i++) if(num % i === 0) return false; 
    return num > 1;
  };

  const calculateSighting = (coord: string): SightingData | null => {
    const parts = coord.split(':').map(Number);
    const C = parts[0];
    const V = parts[1] || 1;

    if (isNaN(C) || C < 1 || C > 114) return null;

    // FRONT SIDE CALCULATIONS
    const theta = ((C - 1) / 114) * 360;
    const radius = V / HORIZON_LIMIT;
    const altitude = 90 - (radius * 90);
    const isMuqattat = MUQATTAT_CHAPTERS.has(C);
    const lightFreq = isMuqattat ? (PHI * (C / 114)).toFixed(4) : "0.0000";

    // Rotational Delta Logic (Shortest Path)
    const currentAngle = alidadeRotationRef.current % 360;
    let diff = theta - currentAngle;
    if (diff > 180) diff -= 360;
    if (diff < -180) diff += 360;

    // BACK SIDE CALCULATIONS
    const radAlt = (altitude * Math.PI) / 180;
    const radZenith = ((90 - altitude) * Math.PI) / 180;

    const umbraRecta = altitude === 0 ? 99.9 : Math.tan(radZenith);
    const umbraVersa = altitude === 90 ? 0.0 : 1 / Math.tan(radAlt);
    const mizanConstant = (C * V) / (114 * 286);
    const manzil = Math.floor(((C - 1) / 114) * 7) + 1;
    const entropy = Math.abs(Math.sin(theta * Math.PI / 180) * radius);

    return {
      front: {
        coordinate: `${C}:${V}`,
        lightFreq,
        theta,
        radius,
        altitude,
        symbol: isMuqattat ? '✦' : '◎',
        sweepDelta: Math.abs(diff),
        sweepDirection: diff >= 0 ? 'clockwise' : 'counter-clockwise',
        isPrime: isPrime(C)
      },
      back: {
        umbraRecta,
        umbraVersa,
        mizanConstant,
        manzil,
        entropy
      }
    };
  };

  const updateWithCoord = (coord: string) => {
    const result = calculateSighting(coord);
    if (result) {
      setSighting(result);
      // Shortest path interpolation
      const current = alidadeRotationRef.current;
      const normalize = (a: number) => ((a % 360) + 360) % 360;
      let diff = normalize(result.front.theta) - normalize(current);
      if (diff > 180) diff -= 360;
      if (diff < -180) diff += 360;

      const target = current + diff;
      alidadeRotationRef.current = target;
      setAlidadeRotation(target);
      setQuery(coord);
    }
  };

  useEffect(() => { updateWithCoord(query); }, []);

  const handleSearch = (e: React.FormEvent) => {
    e.preventDefault();
    updateWithCoord(query);
  };

  const handleRandom = () => {
    const randomSurah = Math.floor(Math.random() * 114) + 1;
    const maxAyahs = BUBBLE_BLOCK_MAPPING_RAW[randomSurah as keyof typeof BUBBLE_BLOCK_MAPPING_RAW] || 7;
    const randomAyah = Math.floor(Math.random() * maxAyahs) + 1;
    updateWithCoord(`${randomSurah}:${randomAyah}`);
  };

  const handleStep = (delta: number) => {
    const parts = query.split(':').map(Number);
    const C = parts[0];
    let V = parts[1] || 1;
    const maxAyahs = BUBBLE_BLOCK_MAPPING_RAW[C as keyof typeof BUBBLE_BLOCK_MAPPING_RAW] || 286;
    V += delta;
    if (V < 1) V = 1;
    if (V > maxAyahs) V = maxAyahs;
    updateWithCoord(`${C}:${V}`);
  };

  const center = 250;
  const outerRadius = 240;
  const innerRadius = 210;

  return (
    <div className="fixed inset-0 z-[200] flex flex-col lg:flex-row bg-[#030408] animate-in fade-in zoom-in duration-500 overflow-hidden font-sans">
      {/* Sidebar: Mechanical Visual Dashboard */}
      <aside className="w-full lg:w-[420px] bg-[#05060a]/98 backdrop-blur-3xl border-b lg:border-r border-cyan-950 p-10 flex flex-col gap-6 overflow-y-auto no-scrollbar shadow-2xl relative">
        {/* Dashboard Frame Symbols (4 Elements) */}
        <div className="absolute top-4 left-4 text-[11px] text-cyan-800 font-mono tracking-[0.2em] select-none">🜄 WATER</div>
        <div className="absolute top-4 right-4 text-[11px] text-amber-800 font-mono tracking-[0.2em] select-none">🜂 FIRE</div>
        <div className="absolute bottom-4 left-4 text-[11px] text-white/20 font-mono tracking-[0.2em] select-none">🜁 LIGHT</div>
        <div className="absolute bottom-4 right-4 text-[11px] text-red-900 font-mono tracking-[0.2em] select-none">🕳 ABYSS</div>

        <div className="flex justify-between items-center border-b border-white/5 pb-6">
          <div className="group cursor-help">
