            <p className="text-cyan-800 text-[10px] font-bold tracking-[0.6em] uppercase mt-2 italic">Instrument of Dual Caustics</p>
          </div>
          <button onClick={onClose} className="p-3 rounded-2xl bg-white/5 text-zinc-600 hover:text-white transition-all border border-white/5 hover:border-white/20">
            <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6" fill="none" viewBox="0 0 24 24" stroke="currentColor">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M6 18L18 6M6 6l12 12" />
            </svg>
          </button>
        </div>

        <div className="flex gap-2 p-1.5 bg-black/60 rounded-2xl border border-white/5">
            <button onClick={() => setActiveSide('FRONT')} className={`flex-1 py-3 text-[10px] font-black uppercase tracking-[0.2em] rounded-xl transition-all ${activeSide === 'FRONT' ? 'bg-cyan-600/20 text-cyan-400 border border-cyan-500/30 shadow-[0_0_20px_rgba(6,182,212,0.1)]' : 'text-zinc-600 hover:text-zinc-400'}`}>Side A: Celestial</button>
            <button onClick={() => setActiveSide('BACK')} className={`flex-1 py-3 text-[10px] font-black uppercase tracking-[0.2em] rounded-xl transition-all ${activeSide === 'BACK' ? 'bg-amber-600/20 text-amber-400 border border-amber-500/30 shadow-[0_0_20px_rgba(245,158,11,0.1)]' : 'text-zinc-600 hover:text-zinc-400'}`}>Side B: Mathematical</button>
        </div>

        <div className="flex flex-col gap-4">
          <form onSubmit={handleSearch} className="relative group">
            <input type="text" value={query} onChange={(e) => setQuery(e.target.value)} placeholder="[ C : V ]" className="w-full bg-black border border-white/10 rounded-2xl px-8 py-5 text-cyan-400 font-mono text-2xl focus:outline-none focus:border-cyan-500/50 transition-all placeholder:text-zinc-900 shadow-[inset_0_0_20px_rgba(0,0,0,1)]" />
            <button type="submit" className="absolute right-4 top-1/2 -translate-y-1/2 bg-cyan-600 hover:bg-cyan-400 text-black font-black px-6 py-2.5 rounded-xl transition-all uppercase text-[11px] tracking-widest active:scale-95 shadow-xl">Sight</button>
          </form>
          <div className="flex gap-2 h-14">
            <button onClick={() => handleStep(-1)} className="flex-1 bg-zinc-900/40 border border-white/5 hover:border-cyan-500/40 text-white rounded-2xl font-black text-2xl transition-all hover:bg-zinc-800 active:scale-95">-</button>
            <button onClick={handleRandom} className="w-20 bg-zinc-900/40 border border-white/5 hover:border-cyan-500/40 text-cyan-400 flex items-center justify-center rounded-2xl transition-all hover:bg-zinc-800 active:scale-95"><ShuffleIcon /></button>
            <button onClick={() => handleStep(1)} className="flex-1 bg-zinc-900/40 border border-white/5 hover:border-cyan-500/40 text-white rounded-2xl font-black text-2xl transition-all hover:bg-zinc-800 active:scale-95">+</button>
          </div>
        </div>

        {sighting && (
