                    </div>
                    <div className="bg-white/[0.02] p-4 rounded-2xl border border-white/5">
                      <label className="text-[9px] text-zinc-500 uppercase font-black block mb-1 tracking-widest">Theta (Θ)</label>
                      <span className="text-2xl font-mono text-cyan-100 font-bold">{sighting.front.theta.toFixed(2)}°</span>
                    </div>
                  </div>
                  <div className="bg-cyan-950/20 p-4 rounded-2xl border border-cyan-500/10 backdrop-blur-md">
                    <p className="text-[11px] text-zinc-300 italic leading-relaxed font-serif">
                       "The Alidade sweeps <span className="text-cyan-400 font-bold">{sighting.front.sweepDelta.toFixed(1)}°</span> {sighting.front.sweepDirection} to align with the <span className="text-white">Ibrahim Plate</span> at Altitude <span className="text-cyan-400 font-bold">{sighting.front.altitude.toFixed(2)}°</span>."
                    </p>
