             <circle cx={center} cy={center + 32} r={92} fill="none" stroke="rgba(245, 158, 11, 0.12)" strokeWidth="2.5" />

             {/* Chapter Prime Markers (The Stars) */}
             {Array.from({ length: 114 }).map((_, i) => {
               const ch = i + 1;
               if (!isPrime(ch) && !MUQATTAT_CHAPTERS.has(ch)) return null;
               const angle = (i / 114) * 360;
               const r = innerRadius - 20 - (Math.sin(i * 1.5) * 40);
               const p = polarToCartesian(center, center, r, angle);
               const isMuqattat = MUQATTAT_CHAPTERS.has(ch);
               return (
                 <g key={i}>
                   <line x1={center} y1={center} x2={p.x} y2={p.y} stroke="rgba(255,255,255,0.03)" strokeWidth="0.5" />
                   <text x={p.x} y={p.y} textAnchor="middle" dominantBaseline="middle" fill={isMuqattat ? "#06b6d4" : "#444"} fontSize={isMuqattat ? 12 : 8} className={isMuqattat ? 'animate-pulse' : ''}>{isMuqattat ? '✦' : '•'}</text>
                 </g>
               );
             })}
          </g>

          {/* Sighting Indicator (The Active Point ◎) */}
          {sighting && (
            <g style={{ transition: 'transform 0.9s cubic-bezier(0.19, 1, 0.22, 1)', transform: `translate(${polarToCartesian(center, center, (innerRadius * sighting.front.radius), sighting.front.theta).x - center}px, ${polarToCartesian(center, center, (innerRadius * sighting.front.radius), sighting.front.theta).y - center}px)` }} transform={`translate(${center} ${center})`}>
               <g className="animate-in fade-in zoom-in duration-1000">
                   <circle cx={0} cy={0} r="16" fill="none" stroke={activeSide === 'FRONT' ? "#06b6d4" : "#f59e0b"} strokeWidth="1.5" strokeDasharray="3 3" className="animate-[spin_15s_linear_infinite]" />
                   <text x={0} y={0} textAnchor="middle" dominantBaseline="middle" fill={activeSide === 'FRONT' ? "#06b6d4" : "#f59e0b"} fontSize="18" className="font-bold select-none drop-shadow-[0_0_12px_currentColor]">{sighting.front.symbol}</text>
                   {/* Radial Guide Line from Center */}
                   <line x1={-polarToCartesian(center, center, (innerRadius * sighting.front.radius), sighting.front.theta).x + center} y1={-polarToCartesian(center, center, (innerRadius * sighting.front.radius), sighting.front.theta).y + center} x2={0} y2={0} stroke={activeSide === 'FRONT' ? "#06b6d4" : "#f59e0b"} strokeWidth="0.5" strokeOpacity="0.4" />
               </g>
            </g>
          )}

          {/* Alidade (Mechanical Sighting Needle) */}
          <g transform={`rotate(${alidadeRotation} ${center} ${center})`} onPointerDown={(e) => { e.stopPropagation(); setIsDraggingAlidade(true); }} className={`cursor-grab active:cursor-grabbing ${!isDraggingAlidade ? 'transition-transform duration-[1200ms]' : ''}`} style={{ transitionTimingFunction: 'cubic-bezier(0.19, 1, 0.22, 1)' }}>
            <rect x={center - 4.5} y={center - outerRadius - 10} width="9" height={(outerRadius + 10) * 2} fill="#1a1b21" rx="4.5" className="shadow-2xl" stroke="#2a2b35" strokeWidth="1" />
            <rect x={center - 1} y={center - outerRadius - 10} width="2" height={(outerRadius + 10) * 2} fill="#f59e0b" opacity="0.5" />

            {/* Sighting Apertures */}
            <circle cx={center} cy={center - outerRadius + 8} r="5" fill="black" stroke="#f59e0b" strokeWidth="1.5" />
            <circle cx={center} cy={center + outerRadius - 8} r="5" fill="black" stroke="#f59e0b" strokeWidth="1.5" />

            {/* Center Pin Axis */}
            <circle cx={center} cy={center} r={16} fill="#05060a" stroke="#f59e0b" strokeWidth="3" className="shadow-2xl" />
            <circle cx={center} cy={center} r={4} fill="#f59e0b" className="animate-pulse shadow-[0_0_15px_#f59e0b]" />
            <text x={center} y={center - 18} textAnchor="middle" fill="#f59e0b" fontSize="7" fontWeight="900" className="font-mono tracking-tighter uppercase select-none">M-114 Axis</text>
          </g>
        </svg>

        <div className="absolute top-10 right-10 flex flex-col items-end pointer-events-none">
           <span className="text-cyan-400 font-black text-3xl tracking-tighter uppercase italic drop-shadow-[0_0_15px_rgba(6,182,212,0.4)]">Phase Sync</span>
           <span className="text-zinc-800 text-[11px] uppercase font-bold tracking-[0.5em] mt-2">286-HORIZON • CALIBRATED</span>
        </div>
      </main>
    </div>
  );
};

