import React, { useState, useRef, useEffect, useMemo } from 'react';
import { TOTAL_SLICES, CHAPTER_DETAILS, MUQATTAT_CHAPTERS, BUBBLE_BLOCK_MAPPING_RAW } from '../constants.ts';
import { polarToCartesian, colorScale } from '../utils.ts';
import { ShuffleIcon } from './Icons.tsx';

interface AstrolabeModeProps {
  onClose: () => void;
}

interface SightingData {
  front: {
    coordinate: string; // C:V:W:L
    lightFreq: string;
    theta: number;
    radius: number;
    altitude: number;
    symbol: '●' | '▲' | '○';
    sweepDelta: number;
    wordIdx: number;
    letterIdx: number;
  };
  back: {
    umbraRecta: number;
    umbraVersa: number;
    mizanConstant: number;
    symmetryStatus: 'PARITY INTACT' | 'VIOLATION';
    entropy: number;
  };
}

// Compact Roman-like glyph generator for high density labeling
const getCompactGlyph = (n: number) => {
    if (n % 10 === 0) return `${n/10}X`;
    if (n === 1) return "I";
    if (n === 5) return "V";
    return n.toString();
};

const AstrolabeMode: React.FC<AstrolabeModeProps> = ({ onClose }) => {
  const [query, setQuery] = useState('18:1');
  const [sighting, setSighting] = useState<SightingData | null>(null);
  const [activeSide, setActiveSide] = useState<'FRONT' | 'BACK'>('FRONT');
  const [reteRotation, setReteRotation] = useState(0);
  const [alidadeRotation, setAlidadeRotation] = useState(0);
  const [isDraggingRete, setIsDraggingRete] = useState(false);
  const [isDraggingAlidade, setIsDraggingAlidade] = useState(false);

  const alidadeRotationRef = useRef(0);
  const svgRef = useRef<SVGSVGElement>(null);

  const HORIZON_LIMIT = 286;
  const PHI = 1.618;

  const isPrime = (num: number) => {
    for(let i = 2, s = Math.sqrt(num); i <= s; i++) if(num % i === 0) return false; 
    return num > 1;
  };

  const calculateSighting = (coord: string): SightingData | null => {
    const parts = coord.split(':').map(Number);
    const C = parts[0] || 1;
    const V = parts[1] || 1;
    const W = parts[2] || (C * V % 15) + 1; // Deterministic proxy
    const L = parts[3] || (W * 4 % 20) + 1; // Deterministic proxy

    if (isNaN(C) || C < 1 || C > 114) return null;

    const theta = (V / HORIZON_LIMIT) * 360; // Absolute verse position
    const radius = C / 114;
    const altitude = 90 - ((V / HORIZON_LIMIT) * 90);
    const isMuqattat = MUQATTAT_CHAPTERS.has(C);

    // Sweep Logic
    const currentAngle = alidadeRotationRef.current % 360;
    let diff = theta - currentAngle;
    if (diff > 180) diff -= 360;
    if (diff < -180) diff += 360;

    return {
      front: {
        coordinate: `${C}:${V}:${W}:${L}`,
        lightFreq: isMuqattat ? (PHI * (C / 114)).toFixed(4) : "0.0000",
        theta,
        radius,
        altitude,
        symbol: isMuqattat ? '▲' : (isPrime(C) ? '●' : '○'),
        sweepDelta: Math.abs(diff),
        wordIdx: W,
        letterIdx: L
      },
      back: {
        umbraRecta: altitude === 0 ? 99.9 : Math.tan(((90 - altitude) * Math.PI) / 180),
        umbraVersa: altitude === 90 ? 0.0 : 1 / Math.tan((altitude * Math.PI) / 180),
        mizanConstant: (C * V) / (114 * 286),
        symmetryStatus: (C + V) % 2 === 0 ? 'PARITY INTACT' : 'VIOLATION',
        entropy: Math.abs(Math.sin(theta * Math.PI / 180))
      }
    };
  };

  const updateWithCoord = (coord: string) => {
    const result = calculateSighting(coord);
    if (result) {
      setSighting(result);
      const current = alidadeRotationRef.current;
      const normalize = (a: number) => ((a % 360) + 360) % 360;
      let diff = normalize(result.front.theta) - normalize(current);
      if (diff > 180) diff -= 360;
      if (diff < -180) diff += 360;
      const target = current + diff;
      alidadeRotationRef.current = target;
      setAlidadeRotation(target);
      setQuery(coord);
    }
  };

  useEffect(() => { updateWithCoord(query); }, []);

  const center = 250;
  const outerRadius = 240;
  const materRadius = 215;
  const reteRadius = 190;
  const innerDialsRadius = 60;

  return (
    <div className="fixed inset-0 z-[200] flex flex-col lg:flex-row bg-[#050608] animate-in fade-in zoom-in duration-700 overflow-hidden font-mono">
      {/* Sidebar Dashboard */}
      <aside className="w-full lg:w-[420px] bg-black/95 backdrop-blur-3xl border-b lg:border-r border-zinc-800 p-8 flex flex-col gap-6 overflow-y-auto no-scrollbar shadow-2xl relative">
        <div className="flex justify-between items-center border-b border-white/5 pb-4">
          <div>
            <h2 className="text-3xl font-black text-white tracking-tighter uppercase italic leading-none">MIZAN-114</h2>
            <p className="text-zinc-500 text-[9px] font-bold tracking-[0.4em] uppercase mt-2">Precision Instrument Calibration</p>
          </div>
          <button onClick={onClose} className="p-2 rounded-xl bg-white/5 text-zinc-600 hover:text-white border border-white/5">
            <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6" fill="none" viewBox="0 0 24 24" stroke="currentColor">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M6 18L18 6M6 6l12 12" />
            </svg>
          </button>
        </div>

        <div className="flex gap-1 p-1 bg-zinc-900/50 rounded-xl border border-white/5">
            <button onClick={() => setActiveSide('FRONT')} className={`flex-1 py-2 text-[10px] font-black uppercase tracking-widest rounded-lg transition-all ${activeSide === 'FRONT' ? 'bg-amber-600/20 text-amber-400 border border-amber-500/30' : 'text-zinc-600 hover:text-zinc-400'}`}>Side A: Celestial</button>
            <button onClick={() => setActiveSide('BACK')} className={`flex-1 py-2 text-[10px] font-black uppercase tracking-widest rounded-lg transition-all ${activeSide === 'BACK' ? 'bg-fuchsia-600/20 text-fuchsia-400 border border-fuchsia-500/30' : 'text-zinc-600 hover:text-zinc-400'}`}>Side B: Math</button>
        </div>

        <form onSubmit={(e) => { e.preventDefault(); updateWithCoord(query); }} className="relative">
          <input type="text" value={query} onChange={(e) => setQuery(e.target.value)} placeholder="C:V:W:L" className="w-full bg-black border border-white/10 rounded-xl px-6 py-4 text-amber-500 font-mono text-xl focus:outline-none focus:border-amber-500/50 transition-all shadow-[inset_0_0_15px_rgba(0,0,0,1)]" />
          <button type="submit" className="absolute right-3 top-1/2 -translate-y-1/2 bg-amber-600 hover:bg-amber-500 text-black font-black px-4 py-2 rounded-lg transition-all uppercase text-[10px] tracking-widest">Sight</button>
        </form>

        {sighting && (
          <div className="space-y-6 animate-in fade-in slide-in-from-bottom duration-1000">
            <div className="bg-zinc-900/40 p-5 rounded-2xl border border-white/5">
                <div className="flex justify-between items-center mb-4">
                    <span className="text-[10px] font-black text-amber-600 uppercase tracking-widest">Instrument Readout</span>
                    <span className="text-xl font-bold text-white">{sighting.front.symbol} {sighting.front.coordinate}</span>
                </div>
                <div className="grid grid-cols-2 gap-4 text-sm">
                    <div className="space-y-1">
                        <label className="text-[9px] text-zinc-500 uppercase">Master Theta</label>
                        <p className="text-amber-200 font-bold">{sighting.front.theta.toFixed(2)}°</p>
                    </div>
                    <div className="space-y-1">
                        <label className="text-[9px] text-zinc-500 uppercase">Altitude (φ)</label>
                        <p className="text-amber-200 font-bold">{sighting.front.altitude.toFixed(2)}°</p>
                    </div>
                </div>
                <div className="mt-4 p-3 bg-black/50 rounded-lg border border-white/5 italic text-[10px] text-zinc-400">
                    "The Alidade sweeps {sighting.front.sweepDelta.toFixed(1)}° to align with Chapter {query.split(':')[0]}."
                </div>
            </div>

            <div className="grid grid-cols-2 gap-3">
                <div className="bg-zinc-900/40 p-4 rounded-xl border border-white/5">
                    <label className="text-[9px] text-zinc-600 uppercase font-black block mb-1">Word Index</label>
                    <span className="text-lg font-bold text-white">{sighting.front.wordIdx}</span>
                </div>
                <div className="bg-zinc-900/40 p-4 rounded-xl border border-white/5">
                    <label className="text-[9px] text-zinc-600 uppercase font-black block mb-1">Letter Index</label>
                    <span className="text-lg font-bold text-white">{sighting.front.letterIdx}</span>
                </div>
            </div>

            <div className="pt-4 border-t border-white/5">
                <h4 className="text-[10px] font-black text-zinc-700 uppercase tracking-widest mb-4">Symbol Legend</h4>
                <div className="grid grid-cols-2 gap-y-2 text-[10px] text-zinc-500">
                    <div className="flex items-center gap-2"><span>●</span> Prime Chapter</div>
                    <div className="flex items-center gap-2"><span>○</span> Composite Chapter</div>
                    <div className="flex items-center gap-2"><span>▲</span> Muqatta'at Anchor</div>
                    <div className="flex items-center gap-2"><span>║</span> Singularity Point</div>
                    <div className="flex items-center gap-2"><span>⟂</span> Opposition (180°)</div>
                    <div className="flex items-center gap-2"><span>⊙</span> Axis/Center Pin</div>
                </div>
            </div>
          </div>
        )}
      </aside>

      {/* Main View: Interactive Mechanical Instrument */}
      <main className="flex-1 relative flex items-center justify-center p-6">
        <svg ref={svgRef} viewBox="0 0 500 500" className={`w-full h-full max-w-[85vh] transition-transform duration-[2000ms] cubic-bezier(0.2, 0.8, 0.2, 1) ${activeSide === 'BACK' ? 'rotate-[180deg]' : ''}`}>

          {/* Mater (Fixed Frame) */}
          <circle cx={center} cy={center} r={outerRadius} fill="#0a0b0e" stroke="#1c1d25" strokeWidth="18" />
          <circle cx={center} cy={center} r={outerRadius - 8} fill="none" stroke="#2a2b35" strokeWidth="0.5" />

          {/* Horizon (Limbus) - 286 Scale */}
          {Array.from({ length: 286 }).map((_, i) => {
            const angle = (i / 286) * 360;
            const isMajor = i % 26 === 0;
            const isLabel = i % 26 === 0;
            const r1 = outerRadius - (isMajor ? 16 : 8);
            const p1 = polarToCartesian(center, center, r1, angle);
            const p2 = polarToCartesian(center, center, outerRadius - 1, angle);
            const labelPos = polarToCartesian(center, center, outerRadius + 12, angle);
            return (
              <g key={`horizon-${i}`}>
                <line x1={p1.x} y1={p1.y} x2={p2.x} y2={p2.y} stroke={isMajor ? "#f59e0b" : "#444"} strokeWidth={isMajor ? 1.5 : 0.5} />
                {isLabel && (
                  <text x={labelPos.x} y={labelPos.y} textAnchor="middle" dominantBaseline="middle" fill="#666" fontSize="7" fontWeight="bold" transform={`rotate(${angle} ${labelPos.x} ${labelPos.y})`}>
                    {i === 0 ? 286 : i}
                  </text>
                )}
              </g>
            );
          })}

          {/* Chapter Shell (Mater Rings) - 114 Slices */}
          <g opacity="0.4">
            {Array.from({ length: 114 }).map((_, i) => {
              const ch = i + 1;
              const angle = (i / 114) * 360;
              const isPrimeCh = isPrime(ch);
              const isMuqattat = MUQATTAT_CHAPTERS.has(ch);
              const p1 = polarToCartesian(center, center, materRadius - 20, angle);
              const p2 = polarToCartesian(center, center, materRadius, angle);
              return (
                <g key={`ch-shell-${i}`}>
                  <line x1={p1.x} y1={p1.y} x2={p2.x} y2={p2.y} stroke="#333" strokeWidth="0.5" />
                  <circle cx={p2.x} cy={p2.y} r={isPrimeCh ? 1.5 : 0.5} fill={isPrimeCh ? "#fff" : "#444"} />
                  {isMuqattat && <path d={`M ${p2.x} ${p2.y-4} L ${p2.x-3} ${p2.y+1} L ${p2.x+3} ${p2.y+1} Z`} fill="none" stroke="#06b6d4" strokeWidth="0.5" />}
                </g>
              );
            })}
          </g>

          {/* Almucantars (Concentric Verse Circles) */}
          {Array.from({ length: 10 }).map((_, i) => (
            <circle key={`alm-${i}`} cx={center} cy={center} r={((materRadius - innerDialsRadius) / 10) * (i + 1) + innerDialsRadius} fill="none" stroke="#222" strokeWidth="0.5" />
          ))}

          {/* Rete (Celestial Web) */}
          <g transform={`rotate(${reteRotation} ${center} ${center})`} onPointerDown={(e) => { e.stopPropagation(); setIsDraggingRete(true); }} className="cursor-grab active:cursor-grabbing transition-transform duration-[1500ms] cubic-bezier(0.19, 1, 0.22, 1)">
             <circle cx={center} cy={center} r={reteRadius} fill="none" stroke="rgba(245, 158, 11, 0.15)" strokeWidth="1.2" />
             {/* Ecliptic / Zodiac Ring */}
             <circle cx={center} cy={center + 25} r={80} fill="none" stroke="rgba(255, 255, 255, 0.05)" strokeWidth="1" />

             {/* Muqatta'at "Stars" on Rete */}
             {Array.from(MUQATTAT_CHAPTERS).map((chId, i) => {
               const angle = ((chId-1) / 114) * 360;
               const r = reteRadius - 20 - (i % 5 * 12);
               const p = polarToCartesian(center, center, r, angle);
               return (
                 <g key={`rete-star-${chId}`}>
                   <line x1={center} y1={center} x2={p.x} y2={p.y} stroke="rgba(255,255,255,0.03)" strokeWidth="0.5" />
                   <text x={p.x} y={p.y} textAnchor="middle" dominantBaseline="middle" fill="#06b6d4" fontSize="10" className="animate-pulse">▲</text>
                 </g>
               );
             })}
          </g>

          {/* Inner Dials: Word / Letter Micro-rings */}
          <circle cx={center} cy={center} r={innerDialsRadius} fill="#050608" stroke="#333" strokeWidth="1" />
          {Array.from({ length: 60 }).map((_, i) => {
             const angle = i * 6;
             const p1 = polarToCartesian(center, center, innerDialsRadius - 5, angle);
             const p2 = polarToCartesian(center, center, innerDialsRadius - 2, angle);
             return <line key={`word-tick-${i}`} x1={p1.x} y1={p1.y} x2={p2.x} y2={p2.y} stroke="#444" strokeWidth="0.5" />;
          })}
          <circle cx={center} cy={center} r={innerDialsRadius - 15} fill="none" stroke="#222" strokeWidth="0.5" />

          {/* Sighting Indicator & Active Vector Line */}
          {sighting && (
            <g className="animate-in fade-in duration-500">
               {/* Radial Verse Vector */}
               <line x1={center} y1={center} x2={polarToCartesian(center, center, outerRadius, sighting.front.theta).x} y2={polarToCartesian(center, center, outerRadius, sighting.front.theta).y} stroke={parseInt(query.split(':')[1]) % 2 === 0 ? "#333" : "#fff"} strokeWidth="0.5" strokeOpacity="0.3" />

               {/* Sighting Point (◎) */}
               <g style={{ transition: 'transform 0.8s cubic-bezier(0.19, 1, 0.22, 1)', transform: `translate(${polarToCartesian(center, center, (innerDialsRadius + (materRadius - innerDialsRadius) * sighting.front.radius), sighting.front.theta).x - center}px, ${polarToCartesian(center, center, (innerDialsRadius + (materRadius - innerDialsRadius) * sighting.front.radius), sighting.front.theta).y - center}px)` }} transform={`translate(${center} ${center})`}>
                   <circle cx={0} cy={0} r="12" fill="none" stroke="#f59e0b" strokeWidth="1" strokeDasharray="2 2" className="animate-[spin_10s_linear_infinite]" />
                   <text x={0} y={0} textAnchor="middle" dominantBaseline="middle" fill="#f59e0b" fontSize="12" fontWeight="black" className="select-none">◎</text>
               </g>
            </g>
          )}

          {/* Alidade (Mechanical Sighting Ruler) */}
          <g transform={`rotate(${alidadeRotation} ${center} ${center})`} onPointerDown={(e) => { e.stopPropagation(); setIsDraggingAlidade(true); }} className="cursor-grab active:cursor-grabbing transition-transform duration-[1200ms] cubic-bezier(0.19, 1, 0.22, 1)">
            {/* The Bar */}
            <path d={`M ${center-5} ${center - outerRadius} L ${center+5} ${center - outerRadius} L ${center+8} ${center} L ${center+5} ${center + outerRadius} L ${center-5} ${center + outerRadius} L ${center-8} ${center} Z`} fill="#111" stroke="#444" strokeWidth="1" />
            <line x1={center} y1={center - outerRadius} x2={center} y2={center + outerRadius} stroke="#f59e0b" strokeWidth="0.5" strokeOpacity="0.5" />

            {/* Scale on Alidade */}
            {Array.from({ length: 11 }).map((_, i) => (
              <line key={`scale-${i}`} x1={center - 3} y1={center - (i * 20)} x2={center + 3} y2={center - (i * 20)} stroke="#555" strokeWidth="0.5" />
            ))}

            {/* Tip Sighting Aperture */}
            <circle cx={center} cy={center - outerRadius + 10} r="6" fill="black" stroke="#f59e0b" strokeWidth="1.5" />
            <circle cx={center} cy={center - outerRadius + 10} r="2" fill="#f59e0b" />

            {/* Center Axis Pin (⊙) */}
            <circle cx={center} cy={center} r={14} fill="#050608" stroke="#f59e0b" strokeWidth="2.5" className="shadow-2xl" />
            <circle cx={center} cy={center} r={3} fill="#f59e0b" className="animate-pulse shadow-[0_0_10px_#f59e0b]" />
            <text x={center} y={center + 24} textAnchor="middle" fill="#f59e0b" fontSize="6" fontWeight="900" className="uppercase tracking-tighter opacity-60">M-114 Axis ⊙</text>
          </g>
        </svg>

        {/* Legend Overlay Top Right */}
        <div className="absolute top-10 right-10 flex flex-col items-end pointer-events-none">
           <span className="text-amber-500 font-black text-2xl tracking-tighter uppercase italic drop-shadow-[0_0_10px_rgba(245,158,11,0.3)]">Phase Sync</span>
           <span className="text-zinc-700 text-[9px] uppercase font-bold tracking-[0.4em] mt-1">286-HORIZON • INSTRUMENT CALIBRATED</span>
        </div>
      </main>
    </div>
  );
