    barrierStatus: 'PENETRATED' | 'GUARDED';
    manzil: number;
    singularity: number; // determinant proxy
  };
}

const AstrolabeMode: React.FC<AstrolabeModeProps> = ({ onClose }) => {
  const [query, setQuery] = useState('12:100');
  const [sighting, setSighting] = useState<SightingData | null>(null);
  const [activeSide, setActiveSide] = useState<'FRONT' | 'BACK'>('FRONT');
  const [alidadeRotation, setAlidadeRotation] = useState(0);
  const alidadeRotationRef = useRef(0);
  const svgRef = useRef<SVGSVGElement>(null);

  const HORIZON_LIMIT = 286;
  const PHI = 1.618;

  const isPrime = (num: number) => {
    for(let i = 2, s = Math.sqrt(num); i <= s; i++) if(num % i === 0) return false; 
    return num > 1;
  };

  const calculateSighting = (coord: string): SightingData | null => {
    const parts = coord.split(':').map(Number);
    const C = parts[0] || 1;
    const V = parts[1] || 1;
    const W = parts[2] || 1;
    const L = parts[3] || 1;

    if (isNaN(C) || C < 1 || C > 114) return null;

    // KINEMATICS: Axis Origin (0,0,0)
    // Theta = absolute chapter position
    const theta = ((C - 1) / 114) * 360;
    // Radius = normalized verse depth on 286-horizon
    const radius = V / HORIZON_LIMIT;
    const altitude = 90 - (radius * 90);
    const isMuqattat = MUQATTAT_CHAPTERS.has(C);

    // Sweep Logic
    const current = alidadeRotationRef.current % 360;
    let diff = theta - current;
    if (diff > 180) diff -= 360;
    if (diff < -180) diff += 360;

    // Symbolic Mapping
    const symbol = isMuqattat ? '✦' : '◎';
    const isPr = isPrime(C);

    // Mathematical Scale
    const radAlt = (altitude * Math.PI) / 180;
    const radZenith = ((90 - altitude) * Math.PI) / 180;
    const umbraRecta = altitude === 0 ? 0 : Math.tan(radZenith);
    const umbraVersa = altitude === 90 ? 0 : 1 / Math.tan(radAlt);
    const mizanConstant = (C * V) / (114 * 286);
    const manzil = Math.floor(((C - 1) / 114) * 7) + 1;
    const singularity = Math.abs(Math.sin(radAlt) * Math.cos(radZenith));

    return {
      front: {
        coordinate: `${C}:${V}${W > 1 ? `:${W}` : ''}${L > 1 ? `:${L}` : ''}`,
        lightFreq: isMuqattat ? (PHI * (C / 114)).toFixed(4) : "0.0000",
        theta,
        radius,
        altitude,
        symbol,
        sweepDelta: Math.abs(diff),
        sweepDirection: diff >= 0 ? 'CW' : 'CCW',
        gestation: (V / HORIZON_LIMIT) * 100,
        isPrime: isPr
      },
      back: {
        umbraRecta,
        umbraVersa,
        mizanConstant,
        barrierStatus: altitude < 15 ? 'PENETRATED' : 'GUARDED',
        manzil,
        singularity
      }
    };
  };

  const updateWithCoord = (coord: string) => {
    const result = calculateSighting(coord);
    if (result) {
      setSighting(result);
      const current = alidadeRotationRef.current;
      const normalize = (a: number) => ((a % 360) + 360) % 360;
      let diff = normalize(result.front.theta) - normalize(current);
      if (diff > 180) diff -= 360;
      if (diff < -180) diff += 360;
      const target = current + diff;
      alidadeRotationRef.current = target;
      setAlidadeRotation(target);
      setQuery(coord);
    }
  };

  useEffect(() => { updateWithCoord(query); }, []);

  const handleStep = (delta: number) => {
    const parts = query.split(':').map(Number);
    const C = parts[0] || 1;
    let V = parts[1] || 1;
    const maxV = BUBBLE_BLOCK_MAPPING_RAW[C as keyof typeof BUBBLE_BLOCK_MAPPING_RAW] || 7;
    V = Math.min(maxV, Math.max(1, V + delta));
    updateWithCoord(`${C}:${V}`);
  };

  const handleRandom = () => {
    const C = Math.floor(Math.random() * 114) + 1;
    const maxV = BUBBLE_BLOCK_MAPPING_RAW[C as keyof typeof BUBBLE_BLOCK_MAPPING_RAW] || 7;
    const V = Math.floor(Math.random() * maxV) + 1;
    updateWithCoord(`${C}:${V}`);
  };

  const center = 250;
  const outerRadius = 240;
  const shellRadius = 210;
  const innerRadius = 180;
  const coreRadius = 45;

  return (
    <div className="fixed inset-0 z-[200] flex flex-col lg:flex-row bg-[#020306] animate-in fade-in duration-500 overflow-hidden font-mono text-zinc-400">
      {/* Visual Dashboard Sidebar */}
      <aside className="w-full lg:w-[420px] bg-black border-b lg:border-r border-zinc-800 p-8 flex flex-col gap-6 overflow-y-auto no-scrollbar relative shadow-2xl">
        {/* Elemental Framing Symbols */}
        <div className="absolute top-4 left-4 text-[10px] text-blue-900/60">🜄 WATER</div>
        <div className="absolute top-4 right-4 text-[10px] text-cyan-900/60">🜁 LIGHT</div>
        <div className="absolute bottom-4 left-4 text-[10px] text-orange-900/60">🜂 FIRE</div>
        <div className="absolute bottom-4 right-4 text-[10px] text-zinc-900/60">🕳 ABYSS</div>

        <div className="flex justify-between items-center border-b border-zinc-800 pb-6">
          <div className="group">
            <h2 className="text-3xl font-black text-white tracking-tighter uppercase italic leading-none group-hover:text-amber-500 transition-colors">MIZAN-114</h2>
            <p className="text-zinc-600 text-[9px] font-bold tracking-[0.4em] uppercase mt-2">Dual-Sided Precision Analog</p>
          </div>
          <button onClick={onClose} className="p-3 rounded-full bg-zinc-900/50 hover:bg-zinc-800 text-zinc-500 hover:text-white border border-zinc-800 transition-all">
            <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6" fill="none" viewBox="0 0 24 24" stroke="currentColor">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M6 18L18 6M6 6l12 12" />
            </svg>
          </button>
        </div>

        <div className="flex gap-1 p-1 bg-zinc-900/40 rounded-xl border border-zinc-800">
            <button onClick={() => setActiveSide('FRONT')} className={`flex-1 py-2 text-[10px] font-black uppercase tracking-widest rounded-lg transition-all ${activeSide === 'FRONT' ? 'bg-amber-600/20 text-amber-500 border border-amber-500/30' : 'text-zinc-600'}`}>CELESTIAL FACE</button>
            <button onClick={() => setActiveSide('BACK')} className={`flex-1 py-2 text-[10px] font-black uppercase tracking-widest rounded-lg transition-all ${activeSide === 'BACK' ? 'bg-fuchsia-600/20 text-fuchsia-500 border border-fuchsia-500/30' : 'text-zinc-600'}`}>MATHEMATICAL SCALE</button>
        </div>

        <div className="space-y-3">
          <form onSubmit={(e) => { e.preventDefault(); updateWithCoord(query); }} className="relative group">
            <input type="text" value={query} onChange={(e) => setQuery(e.target.value)} placeholder="C : V" className="w-full bg-black border border-zinc-800 rounded-xl px-6 py-4 text-amber-500 text-2xl focus:outline-none focus:border-amber-600 transition-all shadow-inner" />
            <button type="submit" className="absolute right-3 top-1/2 -translate-y-1/2 bg-amber-600 hover:bg-amber-500 text-black font-black px-4 py-2 rounded-lg text-[10px] tracking-widest uppercase">Sight</button>
          </form>
          <div className="flex gap-2">
            <button onClick={() => handleStep(-1)} className="flex-1 bg-zinc-900/50 hover:bg-zinc-800 py-3 rounded-xl border border-zinc-800 text-white font-black text-xl">-</button>
            <button onClick={handleRandom} className="w-16 bg-zinc-900/50 hover:bg-zinc-800 flex items-center justify-center rounded-xl border border-zinc-800 text-amber-500"><ShuffleIcon /></button>
            <button onClick={() => handleStep(1)} className="flex-1 bg-zinc-900/50 hover:bg-zinc-800 py-3 rounded-xl border border-zinc-800 text-white font-black text-xl">+</button>
          </div>
        </div>

        {sighting && (
          <div className="flex-1 space-y-6 animate-in fade-in duration-1000">
            {activeSide === 'FRONT' ? (
               <div className="space-y-6">
                  <div className="bg-zinc-900/30 border border-amber-500/10 p-6 rounded-2xl relative overflow-hidden">
                    <div className="absolute top-0 left-0 w-1 h-full bg-amber-600/40"></div>
                    <div className="flex justify-between items-center mb-4">
                        <span className="text-[10px] font-black text-amber-600 uppercase tracking-widest">Sighting [ ۞ ]</span>
                        <span className="text-xl text-white font-bold">{sighting.front.symbol} {sighting.front.coordinate}</span>
                    </div>
                    <div className="grid grid-cols-2 gap-4">
                        <div className="bg-black/50 p-3 rounded-xl border border-white/5">
                            <label className="text-[8px] text-zinc-600 uppercase block mb-1">Θ (Theta)</label>
                            <span className="text-lg font-bold text-amber-100">{sighting.front.theta.toFixed(2)}°</span>
                        </div>
                        <div className="bg-black/50 p-3 rounded-xl border border-white/5">
                            <label className="text-[8px] text-zinc-600 uppercase block mb-1">R (Radius)</label>
                            <span className="text-lg font-bold text-amber-100">{sighting.front.radius.toFixed(4)}</span>
                        </div>
                    </div>
                    <div className="mt-4 p-3 bg-white/5 rounded-lg border border-white/5 text-[10px] italic text-zinc-500 leading-relaxed">
                       "The Alidade sweeps <span className="text-amber-500">{sighting.front.sweepDelta.toFixed(1)}°</span> {sighting.front.sweepDirection} to align with Chapter {query.split(':')[0]} at Altitude <span className="text-amber-500">{sighting.front.altitude.toFixed(2)}°</span>."
                    </div>
                  </div>

                  <div className="grid grid-cols-2 gap-3">
                    <div className="bg-zinc-950 p-4 rounded-xl border border-white/5">
                        <span className="text-[9px] text-zinc-600 uppercase font-black block mb-1 tracking-widest">Light Freq</span>
                        <span className="text-xl font-bold text-cyan-400">{sighting.front.lightFreq} Hz</span>
                    </div>
                    <div className="bg-zinc-950 p-4 rounded-xl border border-white/5">
                        <span className="text-[9px] text-zinc-600 uppercase font-black block mb-1 tracking-widest">Chapter Type</span>
                        <span className="text-xl font-bold text-white">{sighting.front.isPrime ? '● PRIME' : '○ COMP'}</span>
                    </div>
                  </div>

                  <div className="space-y-2">
                    <div className="flex justify-between text-[9px] font-black tracking-widest text-zinc-500 uppercase">
                        <span>Gestation Progress</span>
                        <span>{sighting.front.gestation.toFixed(1)}%</span>
                    </div>
                    <div className="h-1.5 w-full bg-zinc-900 rounded-full overflow-hidden border border-white/5">
                        <div className="h-full bg-amber-500 shadow-[0_0_10px_#f59e0b] transition-all duration-1000" style={{ width: `${sighting.front.gestation}%` }}></div>
                    </div>
                  </div>
               </div>
            ) : (
               <div className="space-y-6">
                  <div className="bg-zinc-900/30 border border-fuchsia-500/10 p-6 rounded-2xl relative overflow-hidden">
                    <div className="absolute top-0 left-0 w-1 h-full bg-fuchsia-600/40"></div>
                    <div className="flex justify-between items-center mb-6">
                        <span className="text-[10px] font-black text-fuchsia-600 uppercase tracking-widest">Mathematical Mirror</span>
                        <span className="text-[10px] font-mono text-fuchsia-400">M-CONSTANT: {sighting.back.mizanConstant.toFixed(8)}</span>
                    </div>
                    <div className="grid grid-cols-2 gap-4">
                        <div className="bg-black/50 p-4 rounded-xl border border-white/5">
                            <label className="text-[8px] text-zinc-600 uppercase block mb-1">Umbra Recta (V)</label>
                            <span className="text-xl font-bold text-fuchsia-100">{sighting.back.umbraRecta.toFixed(4)}</span>
                        </div>
                        <div className="bg-black/50 p-4 rounded-xl border border-white/5">
                            <label className="text-[8px] text-zinc-600 uppercase block mb-1">Umbra Versa (H)</label>
                            <span className="text-xl font-bold text-fuchsia-100">{sighting.back.umbraVersa.toFixed(4)}</span>
                        </div>
                    </div>
                  </div>

                  <div className="bg-zinc-950 border border-fuchsia-500/20 p-5 rounded-2xl space-y-4">
                    <div className="flex justify-between items-center">
                        <span className="text-[10px] text-zinc-600 uppercase font-black tracking-widest">37:7 Guard Status</span>
                        <span className={`text-[10px] font-black px-3 py-1 rounded border ${sighting.back.barrierStatus === 'PENETRATED' ? 'bg-red-500/10 border-red-500/40 text-red-500' : 'bg-emerald-500/10 border-emerald-500/40 text-emerald-500'}`}>{sighting.back.barrierStatus}</span>
                    </div>
                    <div className="h-px bg-white/5"></div>
                    <div className="flex justify-between items-center">
                        <span className="text-[10px] text-zinc-600 uppercase font-black tracking-widest">Singularity Index</span>
                        <span className="text-lg font-bold text-white">║ {sighting.back.singularity.toFixed(6)}</span>
                    </div>
                    <div className="h-px bg-white/5"></div>
                    <div className="flex justify-between items-center">
                        <span className="text-[10px] text-zinc-600 uppercase font-black tracking-widest">Manzil Alignment</span>
                        <span className="text-lg font-bold text-fuchsia-400">Layer {sighting.back.manzil}</span>
                    </div>
                  </div>
               </div>
            )}

            <div className="pt-6 border-t border-zinc-800">
               <h4 className="text-[10px] font-black text-zinc-700 uppercase tracking-widest mb-4">Legend System [ ⊙ ]</h4>
               <div className="grid grid-cols-2 gap-y-3 text-[9px] text-zinc-600 uppercase">
                  <div className="flex items-center gap-2"><span>●</span> Prime Index</div>
                  <div className="flex items-center gap-2"><span>○</span> Composite</div>
                  <div className="flex items-center gap-2"><span>▲</span> Muqatta'at Anchor</div>
                  <div className="flex items-center gap-2"><span>║</span> Singularity</div>
                  <div className="flex items-center gap-2"><span>⟂</span> Opposition (180°)</div>
                  <div className="flex items-center gap-2"><span>⊙</span> Center Pin</div>
               </div>
            </div>
          </div>
        )}
      </aside>

      {/* Main Interactive Instrument */}
      <main className="flex-1 relative flex items-center justify-center p-6 lg:p-12">
        <svg ref={svgRef} viewBox="0 0 500 500" className={`w-full h-full max-w-[85vh] transition-transform duration-[1500ms] cubic-bezier(0.2, 0.8, 0.2, 1) ${activeSide === 'BACK' ? 'rotate-[180deg]' : ''}`}>
          {/* Mater Body */}
          <circle cx={center} cy={center} r={outerRadius} fill="#0a0b0e" stroke="#1a1b21" strokeWidth="20" />
          <circle cx={center} cy={center} r={outerRadius - 10} fill="none" stroke="#2a2b35" strokeWidth="0.5" />

          {/* Limbus (Horizon 286 Scale) */}
          {Array.from({ length: 286 }).map((_, i) => {
            const angle = (i / 286) * 360;
            const isMajor = i % 26 === 0;
            const r1 = outerRadius - (isMajor ? 18 : 8);
            const p1 = polarToCartesian(center, center, r1, angle);
            const p2 = polarToCartesian(center, center, outerRadius - 1, angle);
            const labelPos = polarToCartesian(center, center, outerRadius + 14, angle);
            return (
              <g key={`limbus-${i}`}>
                <line x1={p1.x} y1={p1.y} x2={p2.x} y2={p2.y} stroke={isMajor ? "#f59e0b" : "#333"} strokeWidth={isMajor ? 2 : 0.5} />
                {isMajor && (
                  <text x={labelPos.x} y={labelPos.y} textAnchor="middle" dominantBaseline="middle" fill="#555" fontSize="7" fontWeight="black" transform={`rotate(${angle} ${labelPos.x} ${labelPos.y})`}>
                    {i === 0 ? 286 : i}
                  </text>
                )}
              </g>
            );
          })}

          {/* Chapter Shell (114 Slices) */}
          {Array.from({ length: 114 }).map((_, i) => {
            const angle = (i / 114) * 360;
            const chId = i + 1;
            const isPrimeCh = isPrime(chId);
            const isMuqattat = MUQATTAT_CHAPTERS.has(chId);
            const p1 = polarToCartesian(center, center, shellRadius - 15, angle);
            const p2 = polarToCartesian(center, center, shellRadius, angle);
            return (
              <g key={`shell-${i}`} opacity="0.4">
                <line x1={p1.x} y1={p1.y} x2={p2.x} y2={p2.y} stroke="#333" strokeWidth="0.5" />
                <circle cx={p2.x} cy={p2.y} r={isPrimeCh ? 1.5 : 0.5} fill={isPrimeCh ? "#fff" : "#444"} />
                {isMuqattat && <path d={`M ${p2.x} ${p2.y-4} L ${p2.x-3} ${p2.y+1} L ${p2.x+3} ${p2.y+1} Z`} fill="none" stroke="#06b6d4" strokeWidth="0.5" />}
              </g>
            );
          })}

          {/* Almucantars (10 circles representing 286) */}
          {Array.from({ length: 10 }).map((_, i) => (
            <circle key={`alm-${i}`} cx={center} cy={center} r={coreRadius + ((shellRadius - coreRadius) / 10) * (i + 1)} fill="none" stroke="#1a1a1a" strokeWidth="0.5" />
          ))}

          {/* Sighting Logic */}
          {sighting && (
            <g className="animate-in fade-in duration-700">
               {/* Fixed Verse Vector */}
               <line x1={center} y1={center} x2={polarToCartesian(center, center, outerRadius, sighting.front.theta).x} y2={polarToCartesian(center, center, outerRadius, sighting.front.theta).y} stroke="#fff" strokeWidth="0.5" strokeOpacity="0.2" />

               {/* The Particle ◎ */}
               <g style={{ transition: 'transform 0.8s cubic-bezier(0.19, 1, 0.22, 1)', transform: `translate(${polarToCartesian(center, center, coreRadius + (shellRadius - coreRadius) * sighting.front.radius, sighting.front.theta).x - center}px, ${polarToCartesian(center, center, coreRadius + (shellRadius - coreRadius) * sighting.front.radius, sighting.front.theta).y - center}px)` }} transform={`translate(${center} ${center})`}>
                   <circle cx={0} cy={0} r="14" fill="none" stroke="#f59e0b" strokeWidth="1" strokeDasharray="3 3" className="animate-[spin_10s_linear_infinite]" />
                   <text x={0} y={0} textAnchor="middle" dominantBaseline="middle" fill="#f59e0b" fontSize="14" fontWeight="black" className="select-none">{sighting.front.symbol}</text>
               </g>
            </g>
          )}

          {/* Alidade (Mechanical Needle) */}
          <g transform={`rotate(${alidadeRotation} ${center} ${center})`} className="transition-transform duration-[1200ms] cubic-bezier(0.19, 1, 0.22, 1)">
            {/* Structural Bar */}
            <path d={`M ${center-4} ${center - outerRadius} L ${center+4} ${center - outerRadius} L ${center+7} ${center} L ${center+4} ${center + outerRadius} L ${center-4} ${center + outerRadius} L ${center-7} ${center} Z`} fill="#15161a" stroke="#2a2b35" strokeWidth="1.2" />
            <line x1={center} y1={center - outerRadius} x2={center} y2={center + outerRadius} stroke="#f59e0b" strokeWidth="0.4" opacity="0.6" />

            {/* Graduation Scale */}
            {Array.from({ length: 11 }).map((_, i) => (
              <line key={`al-scale-${i}`} x1={center - 3} y1={center - (i * 20)} x2={center + 3} y2={center - (i * 20)} stroke="#444" strokeWidth="0.5" />
            ))}

            {/* Tip Sighting Aperture */}
            <circle cx={center} cy={center - outerRadius + 12} r="6" fill="#000" stroke="#f59e0b" strokeWidth="1.5" />
            <circle cx={center} cy={center - outerRadius + 12} r="2" fill="#f59e0b" />

            {/* Center Axis (⊙) */}
            <circle cx={center} cy={center} r={15} fill="#050608" stroke="#f59e0b" strokeWidth="2.5" className="shadow-2xl" />
            <circle cx={center} cy={center} r={3} fill="#f59e0b" className="animate-pulse shadow-[0_0_15px_#f59e0b]" />
            <text x={center} y={center + 26} textAnchor="middle" fill="#f59e0b" fontSize="6" fontWeight="black" className="uppercase opacity-40">Axis ⊙</text>
          </g>

          {/* Fine Resolution Micro-rings */}
          <g opacity="0.3">
            <circle cx={center} cy={center} r={coreRadius} fill="none" stroke="#333" strokeWidth="1" />
            <circle cx={center} cy={center} r={coreRadius - 8} fill="none" stroke="#222" strokeWidth="0.5" />
            {Array.from({ length: 114 }).map((_, i) => (
               <line key={`fine-${i}`} x1={center} y1={center - coreRadius} x2={center} y2={center - coreRadius + 4} stroke="#444" strokeWidth="0.5" transform={`rotate(${i * (360/114)} ${center} ${center})`} />
            ))}
          </g>
        </svg>

        <div className="absolute top-10 right-10 flex flex-col items-end pointer-events-none">
           <span className="text-amber-500 font-black text-2xl tracking-tighter uppercase italic drop-shadow-[0_0_15px_rgba(245,158,11,0.3)]">Phase Sync</span>
           <span className="text-zinc-800 text-[10px] uppercase font-bold tracking-[0.4em] mt-1">H: 286 • CALIBRATED DEVICE</span>
        </div>
      </main>
    </div>
  );
};

export default AstrolabeMode;

