import React, { useState, useRef, useEffect, useMemo, useCallback } from 'react';
import { TOTAL_SLICES, CHAPTER_DETAILS, MUQATTAT_CHAPTERS, MUQATTAT_LETTERS, SLICE_DATA, BUBBLE_BLOCK_MAPPING_RAW } from '../constants.ts';
import { polarToCartesian, colorScale } from '../utils.ts';
import { ShuffleIcon } from './Icons.tsx';

interface AstrolabeModeProps {
  onClose: () => void;
}

interface SightingData {
  front: {
    coordinate: string;
    lightFreq: string;
    theta: number;
    radius: number;
    altitude: number;
    symbol: string;
    sweepDelta: number;
    sweepDirection: 'clockwise' | 'counter-clockwise';
    gestation: number;
    isPrime: boolean;
  };
  back: {
    umbraRecta: number;   // tan(zenith)
    umbraVersa: number;   // cot(alt)
    mizanConstant: number; // (C*V)/(114*286)
    barrierStatus: 'PENETRATED' | 'GUARDED';
    manzil: number;
    kingdomProximity: number;
  };
}

const AstrolabeMode: React.FC<AstrolabeModeProps> = ({ onClose }) => {
  const [query, setQuery] = useState('12:100');
  const [sighting, setSighting] = useState<SightingData | null>(null);
  const [activeSide, setActiveSide] = useState<'FRONT' | 'BACK'>('FRONT');
  const [alidadeRotation, setAlidadeRotation] = useState(0);
  const alidadeRotationRef = useRef(0);
  const svgRef = useRef<SVGSVGElement>(null);

  const HORIZON_LIMIT = 286;
  const PHI = 1.618;

  const isPrime = (num: number) => {
    for(let i = 2, s = Math.sqrt(num); i <= s; i++) if(num % i === 0) return false; 
    return num > 1;
  };

  const calculateSighting = (coord: string): SightingData | null => {
    const parts = coord.split(':').map(Number);
    const C = parts[0] || 1;
    const V = parts[1] || 1;
    const W = parts[2] || 1;
    const L = parts[3] || 1;

    if (isNaN(C) || C < 1 || C > 114) return null;

    // KINEMATICS: Axis Origin (0,0,0)
    // Theta = absolute chapter position
    const theta = ((C - 1) / 114) * 360;
    // Radius = normalized verse depth on 286-horizon (0 = Zenith, 1 = Horizon)
    const radius = V / HORIZON_LIMIT;
    const altitude = 90 - (radius * 90);
    const isMuqattat = MUQATTAT_CHAPTERS.has(C);

    // Sweep Logic (Shortest Path)
    const current = alidadeRotationRef.current % 360;
    let diff = theta - current;
    if (diff > 180) diff -= 360;
    if (diff < -180) diff += 360;

    // Kingdom Proximity (Distance to 12:100)
    const kC = 12, kV = 100;
    const kTheta = ((kC - 1) / 114) * 360;
    const kRadius = kV / HORIZON_LIMIT;
    const dx = radius * Math.cos(theta * Math.PI / 180) - kRadius * Math.cos(kTheta * Math.PI / 180);
    const dy = radius * Math.sin(theta * Math.PI / 180) - kRadius * Math.sin(kTheta * Math.PI / 180);
    const kingdomProximity = Math.sqrt(dx*dx + dy*dy);

    const radAlt = (altitude * Math.PI) / 180;
    const radZenith = ((90 - altitude) * Math.PI) / 180;

    return {
      front: {
        coordinate: `${C}:${V}${W > 1 ? `:${W}` : ''}${L > 1 ? `:${L}` : ''}`,
        lightFreq: isMuqattat ? (PHI * (C / 114)).toFixed(4) : "0.0000",
        theta,
        radius,
        altitude,
        symbol: isMuqattat ? '✦' : '◎',
        sweepDelta: Math.abs(diff),
        sweepDirection: diff >= 0 ? 'clockwise' : 'counter-clockwise',
        gestation: (V / HORIZON_LIMIT) * 100,
        isPrime: isPrime(C)
      },
      back: {
        umbraRecta: altitude === 0 ? 0 : Math.tan(radZenith),
        umbraVersa: altitude === 90 ? 0 : 1 / Math.tan(radAlt),
        mizanConstant: (C * V) / (114 * 286),
        barrierStatus: altitude < 15 ? 'PENETRATED' : 'GUARDED',
        manzil: Math.floor(((C - 1) / 114) * 7) + 1,
        kingdomProximity
      }
    };
  };

  const updateWithCoord = (coord: string) => {
    const result = calculateSighting(coord);
    if (result) {
      setSighting(result);
      const current = alidadeRotationRef.current;
      const normalize = (a: number) => ((a % 360) + 360) % 360;
      let diff = normalize(result.front.theta) - normalize(current);
      if (diff > 180) diff -= 360;
      if (diff < -180) diff += 360;
      const target = current + diff;
      alidadeRotationRef.current = target;
      setAlidadeRotation(target);
      setQuery(coord);
    }
  };

  useEffect(() => { updateWithCoord(query); }, []);

  const handleStep = (delta: number) => {
    const parts = query.split(':').map(Number);
    const C = parts[0] || 1;
    let V = parts[1] || 1;
    const maxV = BUBBLE_BLOCK_MAPPING_RAW[C as keyof typeof BUBBLE_BLOCK_MAPPING_RAW] || 7;
    V = Math.min(maxV, Math.max(1, V + delta));
    updateWithCoord(`${C}:${V}`);
  };

  const handleRandom = () => {
    const C = Math.floor(Math.random() * 114) + 1;
    const maxV = BUBBLE_BLOCK_MAPPING_RAW[C as keyof typeof BUBBLE_BLOCK_MAPPING_RAW] || 7;
    const V = Math.floor(Math.random() * maxV) + 1;
    updateWithCoord(`${C}:${V}`);
  };

  const center = 250;
  const outerRadius = 240;
  const shellRadius = 210;
  const innerRadius = 180;
  const coreRadius = 50;

  return (
    <div className="fixed inset-0 z-[200] flex flex-col lg:flex-row bg-[#050608] animate-in fade-in duration-700 overflow-hidden font-mono text-amber-50/70">

      {/* Aesthetic Dashboard Sidebar */}
      <aside className="w-full lg:w-[480px] bg-black border-b lg:border-r border-zinc-800 p-8 flex flex-col gap-6 overflow-y-auto no-scrollbar relative shadow-2xl">
        {/* Symbolic Border */}
        <div className="text-center text-amber-600/40 text-xs tracking-widest mb-2 select-none">[ ۞ ۩ ۞ ۩ ۞ ]</div>

        <div className="flex justify-between items-center border-b border-zinc-800 pb-6">
          <div className="group cursor-default">
            <h2 className="text-3xl font-black text-amber-500 tracking-tighter uppercase italic leading-none group-hover:text-amber-300 transition-colors">MIZAN-114</h2>
            <p className="text-zinc-600 text-[9px] font-bold tracking-[0.5em] uppercase mt-2">Instrument of Dual Caustics</p>
          </div>
          <button onClick={onClose} className="p-3 rounded-full bg-zinc-900/50 hover:bg-zinc-800 text-zinc-500 hover:text-white border border-zinc-800 transition-all">
            <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M6 18L18 6M6 6l12 12" /></svg>
          </button>
        </div>

        <div className="flex gap-1 p-1 bg-zinc-950/80 rounded-xl border border-zinc-800">
            <button onClick={() => setActiveSide('FRONT')} className={`flex-1 py-2 text-[10px] font-black uppercase tracking-widest rounded-lg transition-all ${activeSide === 'FRONT' ? 'bg-amber-600/20 text-amber-400 border border-amber-500/30' : 'text-zinc-600'}`}>CELESTIAL FACE</button>
            <button onClick={() => setActiveSide('BACK')} className={`flex-1 py-2 text-[10px] font-black uppercase tracking-widest rounded-lg transition-all ${activeSide === 'BACK' ? 'bg-fuchsia-600/20 text-fuchsia-400 border border-fuchsia-500/30' : 'text-zinc-600'}`}>MATHEMATICAL SCALE</button>
        </div>

        {/* INPUT AND TUNING */}
        <div className="space-y-4">
          <form onSubmit={(e) => { e.preventDefault(); updateWithCoord(query); }} className="relative group">
            <input type="text" value={query} onChange={(e) => setQuery(e.target.value)} placeholder="C : V" className="w-full bg-black border-2 border-zinc-800 rounded-2xl px-8 py-5 text-amber-500 text-3xl font-black focus:outline-none focus:border-amber-600 transition-all shadow-inner placeholder:text-zinc-900" />
            <button type="submit" className="absolute right-4 top-1/2 -translate-y-1/2 bg-amber-600 hover:bg-amber-500 text-black font-black px-6 py-3 rounded-xl text-xs tracking-[0.2em] uppercase active:scale-95 shadow-xl">Sight</button>
          </form>
          <div className="flex gap-3 h-14">
            <button onClick={() => handleStep(-1)} className="flex-1 bg-zinc-900/60 hover:bg-zinc-800 rounded-2xl border border-zinc-700/50 text-white font-black text-2xl transition-all active:scale-95">-</button>
            <button onClick={handleRandom} className="w-20 bg-zinc-900/60 hover:bg-zinc-800 flex items-center justify-center rounded-2xl border border-zinc-700/50 text-amber-500 transition-all active:scale-95"><ShuffleIcon /></button>
            <button onClick={() => handleStep(1)} className="flex-1 bg-zinc-900/60 hover:bg-zinc-800 rounded-2xl border border-zinc-700/50 text-white font-black text-2xl transition-all active:scale-95">+</button>
          </div>
        </div>

        {sighting && (
          <div className="flex-1 space-y-6">
            {/* TWIN PANEL ASCII FRAME */}
            <div className="grid grid-cols-2 gap-4">
              {/* FRONT PANEL */}
              <div className={`p-4 rounded-2xl border transition-all duration-500 ${activeSide === 'FRONT' ? 'bg-amber-900/10 border-amber-500/40 shadow-[0_0_25px_rgba(245,158,11,0.1)]' : 'bg-black/40 border-zinc-800 opacity-40'}`}>
                <div className="text-[9px] font-black text-amber-600 uppercase mb-3 text-center tracking-widest">[ ۞ FRONT ۞ ]</div>
                <div className="space-y-4">
                  <div className="text-center">
                    <div className="text-[8px] text-zinc-500 uppercase tracking-widest mb-1">Theta (Δθ)</div>
                    <div className="text-xl font-bold text-white leading-none">{sighting.front.theta.toFixed(2)}°</div>
                  </div>
                  <div className="text-center">
                    <div className="text-[8px] text-zinc-500 uppercase tracking-widest mb-1">Altitude (φ)</div>
                    <div className="text-xl font-bold text-white leading-none">{sighting.front.altitude.toFixed(2)}°</div>
                  </div>
                  <div className="bg-black/50 p-2 rounded-lg border border-white/5 font-mono text-[7px] leading-tight text-amber-200/60 text-center">
                    Z . . . . .<br/>
                    H . {sighting.front.symbol} . . .<br/>
                    [ SIGHTING ]
                  </div>
                </div>
              </div>

              {/* BACK PANEL */}
              <div className={`p-4 rounded-2xl border transition-all duration-500 ${activeSide === 'BACK' ? 'bg-fuchsia-900/10 border-fuchsia-500/40 shadow-[0_0_25px_rgba(217,70,239,0.1)]' : 'bg-black/40 border-zinc-800 opacity-40'}`}>
                <div className="text-[9px] font-black text-fuchsia-600 uppercase mb-3 text-center tracking-widest">[ ۩ BACK ۩ ]</div>
                <div className="space-y-4">
                  <div className="text-center">
                    <div className="text-[8px] text-zinc-500 uppercase tracking-widest mb-1">Umbra Recta</div>
                    <div className="text-lg font-bold text-white leading-none">{sighting.back.umbraRecta.toFixed(4)}</div>
                  </div>
                  <div className="text-center">
                    <div className="text-[8px] text-zinc-500 uppercase tracking-widest mb-1">Umbra Versa</div>
                    <div className="text-lg font-bold text-white leading-none">{sighting.back.umbraVersa.toFixed(4)}</div>
                  </div>
                  <div className="text-center">
                    <div className="text-[8px] text-zinc-500 uppercase tracking-widest mb-1">M-Constant</div>
                    <div className="text-xs font-bold text-fuchsia-400 leading-none">{sighting.back.mizanConstant.toFixed(8)}</div>
                  </div>
                </div>
              </div>
            </div>

            {/* STATUS SUMMARY */}
            <div className="bg-zinc-950 border border-zinc-800 p-6 rounded-[2rem] space-y-5">
              <div className="flex justify-between items-center">
                <span className="text-[10px] font-black text-zinc-500 uppercase tracking-[0.2em]">37:7 Guard Barrier</span>
                <span className={`text-[10px] font-black px-3 py-1 rounded border ${sighting.back.barrierStatus === 'PENETRATED' ? 'bg-red-950 border-red-500 text-red-500 animate-pulse' : 'bg-emerald-950 border-emerald-500 text-emerald-500'}`}>
                  {sighting.back.barrierStatus}
                </span>
              </div>
              <div className="h-px bg-zinc-800/50"></div>
              <div className="flex justify-between items-center">
                <span className="text-[10px] font-black text-zinc-500 uppercase tracking-[0.2em]">Gestation (Isa-Birth)</span>
                <div className="flex flex-col items-end gap-1.5">
                  <span className="text-lg font-bold text-amber-400 leading-none">{sighting.front.gestation.toFixed(2)}%</span>
                  <div className="w-32 h-1 bg-zinc-900 rounded-full overflow-hidden border border-white/5">
                    <div className="h-full bg-amber-500 shadow-[0_0_10px_#f59e0b] transition-all duration-1000" style={{ width: `${sighting.front.gestation}%` }}></div>
                  </div>
                </div>
              </div>
              <div className="h-px bg-zinc-800/50"></div>
              <div className="flex justify-between items-center">
                <span className="text-[10px] font-black text-zinc-500 uppercase tracking-[0.2em]">Kingdom Proximity</span>
                <span className="text-lg font-bold text-white tracking-tighter">⚖ {sighting.back.kingdomProximity.toFixed(6)}</span>
              </div>
            </div>

            {/* SWEEP NARRATIVE */}
            <div className="p-5 bg-amber-950/10 border-l-4 border-amber-500/50 rounded-r-2xl italic text-[11px] leading-relaxed text-amber-100/70 font-serif">
              "The Alidade begins rotation from current azimuth. Sweeping <span className="text-amber-400 font-bold">{sighting.front.sweepDelta.toFixed(1)}°</span> {sighting.front.sweepDirection}... 
              Sighting the <span className="text-white">Ibrahim Plate</span>... 
              Descending Altitude from Zenith to <span className="text-amber-400 font-bold">{sighting.front.altitude.toFixed(2)}°</span>... 
              Locking into the 286-Horizon Grid."
            </div>
          </div>
        )}

        <div className="mt-auto text-center text-amber-600/40 text-xs tracking-widest select-none">[ ۞ ۩ ۞ ۩ ۞ ]</div>
      </aside>

      {/* Main Interactive Instrument */}
      <main className="flex-1 relative flex items-center justify-center p-6 lg:p-12 overflow-hidden">
        {/* Subtle Ecliptic Guides */}
        <div className="absolute inset-0 pointer-events-none opacity-20 flex items-center justify-center">
            <div className="w-[95%] aspect-square border border-amber-900/30 rounded-full"></div>
            <div className="absolute w-[75%] aspect-square border border-amber-900/20 rounded-full"></div>
            <div className="absolute w-[55%] aspect-square border border-amber-900/10 rounded-full"></div>
        </div>

        <svg ref={svgRef} viewBox="0 0 500 500" className={`w-full h-full max-w-[85vh] transition-transform duration-[2000ms] cubic-bezier(0.2, 0.8, 0.2, 1) ${activeSide === 'BACK' ? 'rotate-[180deg]' : ''}`}>
          {/* Mater Body (Heavy Brass Feel) */}
          <circle cx={center} cy={center} r={outerRadius} fill="#0a0b0e" stroke="#1c1d25" strokeWidth="22" className="shadow-2xl" />
          <circle cx={center} cy={center} r={outerRadius - 11} fill="none" stroke="#f59e0b" strokeWidth="0.8" opacity="0.3" />

          {/* Limbus (Horizon 286 Scale) */}
          {Array.from({ length: 286 }).map((_, i) => {
            const angle = (i / 286) * 360;
            const isMajor = i % 26 === 0;
            const r1 = outerRadius - (isMajor ? 18 : 8);
            const p1 = polarToCartesian(center, center, r1, angle);
            const p2 = polarToCartesian(center, center, outerRadius - 1, angle);
            const labelPos = polarToCartesian(center, center, outerRadius + 14, angle);
            return (
              <g key={`limbus-${i}`}>
                <line x1={p1.x} y1={p1.y} x2={p2.x} y2={p2.y} stroke={isMajor ? "#f59e0b" : "#333"} strokeWidth={isMajor ? 2.5 : 0.5} />
                {isMajor && (
                  <text x={labelPos.x} y={labelPos.y} textAnchor="middle" dominantBaseline="middle" fill="#666" fontSize="8" fontWeight="black" transform={`rotate(${angle} ${labelPos.x} ${labelPos.y})`}>
                    {i === 0 ? 286 : i}
                  </text>
                )}
              </g>
            );
          })}

          {/* Cardinal Marking Symbols */}
          <g className="select-none pointer-events-none">
            <text x={center} y={center - outerRadius - 30} textAnchor="middle" fill="#f59e0b" fontSize="24" fontWeight="bold">۩</text>
            <text x={center + outerRadius + 35} y={center + 8} textAnchor="middle" fill="#f59e0b" fontSize="24" fontWeight="bold">☼</text>
            <text x={center} y={center + outerRadius + 45} textAnchor="middle" fill="#f59e0b" fontSize="24" fontWeight="bold">🕳</text>
            <text x={center - outerRadius - 35} y={center + 8} textAnchor="middle" fill="#f59e0b" fontSize="24" fontWeight="bold">☾</text>
          </g>

          {/* Chapter Shell (114 Slices) */}
          {Array.from({ length: 114 }).map((_, i) => {
            const angle = (i / 114) * 360;
            const chId = i + 1;
            const isPrimeCh = isPrime(chId);
            const isMuqattat = MUQATTAT_CHAPTERS.has(chId);
            const p1 = polarToCartesian(center, center, shellRadius - 20, angle);
            const p2 = polarToCartesian(center, center, shellRadius, angle);
            return (
              <g key={`shell-${i}`} opacity="0.4">
                <line x1={p1.x} y1={p1.y} x2={p2.x} y2={p2.y} stroke="#333" strokeWidth="0.5" />
                <circle cx={p2.x} cy={p2.y} r={isPrimeCh ? 2 : 0.8} fill={isPrimeCh ? "#f59e0b" : "#444"} />
                {isMuqattat && <text x={p2.x} y={p2.y-5} textAnchor="middle" fill="#06b6d4" fontSize="10">✦</text>}
              </g>
            );
          })}

          {/* Almucantars (Concentric Altitude Circles) */}
          {Array.from({ length: 10 }).map((_, i) => (
            <circle key={`alm-${i}`} cx={center} cy={center} r={coreRadius + ((shellRadius - coreRadius) / 10) * (i + 1)} fill="none" stroke="rgba(245, 158, 11, 0.05)" strokeWidth="0.75" />
          ))}

          {/* Active Sighting Vector */}
          {sighting && (
            <g className="animate-in fade-in duration-1000">
               {/* Radial Verse Vector (Path of Sighting) */}
               <line x1={center} y1={center} x2={polarToCartesian(center, center, outerRadius, sighting.front.theta).x} y2={polarToCartesian(center, center, outerRadius, sighting.front.theta).y} stroke="#fff" strokeWidth="0.5" strokeOpacity="0.25" strokeDasharray="4 4" />

               {/* The Sighting Particle ◎ */}
               <g style={{ transition: 'transform 0.9s cubic-bezier(0.19, 1, 0.22, 1)', transform: `translate(${polarToCartesian(center, center, coreRadius + (shellRadius - coreRadius) * sighting.front.radius, sighting.front.theta).x - center}px, ${polarToCartesian(center, center, coreRadius + (shellRadius - coreRadius) * sighting.front.radius, sighting.front.theta).y - center}px)` }} transform={`translate(${center} ${center})`}>
                   <circle cx={0} cy={0} r="18" fill="none" stroke="#f59e0b" strokeWidth="1.5" strokeDasharray="3 3" className="animate-[spin_12s_linear_infinite]" />
                   <text x={0} y={0} textAnchor="middle" dominantBaseline="middle" fill="#f59e0b" fontSize="18" fontWeight="black" className="select-none drop-shadow-[0_0_15px_#f59e0b]">{sighting.front.symbol}</text>
               </g>
            </g>
          )}

          {/* Alidade (The Pointer Needle) */}
          <g transform={`rotate(${alidadeRotation} ${center} ${center})`} className="transition-transform duration-[1500ms] cubic-bezier(0.19, 1, 0.22, 1)">
            {/* Structural Bar (The Brass Rule) */}
            <path d={`M ${center-5} ${center - outerRadius - 10} L ${center+5} ${center - outerRadius - 10} L ${center+8} ${center} L ${center+5} ${center + outerRadius + 10} L ${center-5} ${center + outerRadius + 10} L ${center-8} ${center} Z`} fill="#1a1b21" stroke="#3a3b45" strokeWidth="1.5" className="shadow-2xl" />
            <line x1={center} y1={center - outerRadius - 10} x2={center} y2={center + outerRadius + 10} stroke="#f59e0b" strokeWidth="0.5" opacity="0.6" />

            {/* Fine Calibration on Alidade */}
            {Array.from({ length: 20 }).map((_, i) => (
              <line key={`al-scale-${i}`} x1={center - (i % 5 === 0 ? 5 : 2)} y1={center - outerRadius + (i * 20)} x2={center + (i % 5 === 0 ? 5 : 2)} y2={center - outerRadius + (i * 20)} stroke="#555" strokeWidth="0.5" />
            ))}

            {/* Sighting Aperture Tip (⇈) */}
            <circle cx={center} cy={center - outerRadius + 12} r="8" fill="#000" stroke="#f59e0b" strokeWidth="2" />
            <circle cx={center} cy={center - outerRadius + 12} r="2.5" fill="#f59e0b" />
            <text x={center} y={center - outerRadius - 15} textAnchor="middle" fill="#f59e0b" fontSize="16" fontWeight="bold">⇈</text>

            {/* Center Axis Pin (The Axis ⊙) */}
            <circle cx={center} cy={center} r={18} fill="#0a0b0e" stroke="#f59e0b" strokeWidth="3" className="shadow-2xl" />
            <circle cx={center} cy={center} r={4} fill="#f59e0b" className="animate-pulse shadow-[0_0_20px_#f59e0b]" />
            <text x={center} y={center + 30} textAnchor="middle" fill="#f59e0b" fontSize="7" fontWeight="black" className="uppercase opacity-50 tracking-tighter">Axis ⊙ Pin</text>
          </g>

          {/* Word/Letter Resolution Micro-rings */}
          <g opacity="0.25">
            <circle cx={center} cy={center} r={coreRadius} fill="none" stroke="#666" strokeWidth="1.5" />
            <circle cx={center} cy={center} r={coreRadius - 12} fill="none" stroke="#444" strokeWidth="1" />
            {Array.from({ length: 114 }).map((_, i) => (
               <line key={`micro-${i}`} x1={center} y1={center - coreRadius} x2={center} y2={center - coreRadius + 6} stroke="#555" strokeWidth="0.75" transform={`rotate(${i * (360/114)} ${center} ${center})`} />
            ))}
          </g>
        </svg>

        {/* Global Instrument Metadata */}
        <div className="absolute top-10 right-10 flex flex-col items-end pointer-events-none select-none">
           <span className="text-amber-500 font-black text-3xl tracking-tighter uppercase italic drop-shadow-[0_0_15px_rgba(245,158,11,0.4)]">Phase Sync</span>
           <span className="text-zinc-800 text-[11px] uppercase font-bold tracking-[0.6em] mt-2">H-286 • CALIBRATED ANALOG</span>
        </div>

        {/* Floating Balance Symbol */}
        <div className="absolute bottom-10 left-10 text-amber-900/30 text-6xl select-none">⚖</div>
      </main>
    </div>
  );
};

export default AstrolabeMode;
